	('2258d343-7fd5-46eb-a9f5-1959197b78f3', 'Office Health and Safety', 'CORP132', 'This corporate training program on Office Health and Safety helps participants understand key principles, explore practical workplace examples, and build confidence applying office health and safety in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765250368834-10ja25hu7m2.jpg', 'Active', '2 weeks', 5, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-23 12:16:14.889252+00', NULL, '["Explain the core concepts and importance of Office Health and Safety in a professional environment.", "Recognize common workplace situations where strong office health and safety is critical to success.", "Apply tools, techniques, and best practices related to office health and safety in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in office health and safety.", "Demonstrate growth in key skills developed in this course: Office Health and Safety, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.01255747,0.038334597,0.06304018,0.030532831,-0.020997342,-0.0007129795,0.005824234,0.012184237,0.030918105,0.013352094,0.045389894,-0.041513093,0.001656972,-0.028991742,0.03308526,0.009120118,-0.005113888,-0.010805685,0.03322974,0.0006290775,0.00025960733,0.015109899,-0.00954753,0.08085903,-0.057068463,-0.0023342085,0.018854264,-0.00060537417,0.00450889,0.009716086,0.05177097,-0.030869946,-0.017517852,0.031231137,0.03354277,0.0035607591,-0.018866304,0.025331656,0.02108162,-0.0023913973,-0.007332214,-0.00046955064,0.043969203,0.0511449,-0.009764246,-0.021743806,0.045486216,-0.010582949,0.03164049,0.008722806,-0.018456953,0.0030535841,0.023345094,0.0012649273,-0.027715528,-0.0061944565,-0.0012792245,0.037323255,-0.027065381,0.0014289691,0.06723002,-0.043921046,-0.05283047,0.08692707,0.04