	('0d8e07e4-9d1e-4c83-be17-ab2b239f49a7', 'Coaching Salespeople', 'CORP076', 'This corporate training program on Coaching Salespeople helps participants understand key principles, explore practical workplace examples, and build confidence applying coaching salespeople in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765254784628-4z8q1r0xqj.jpg', 'Active', '6 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:56:27.931167+00', NULL, '["Explain the core concepts and importance of Coaching Salespeople in a professional environment.", "Recognize common workplace situations where strong coaching salespeople is critical to success.", "Apply tools, techniques, and best practices related to coaching salespeople in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in coaching salespeople.", "Demonstrate growth in key skills developed in this course: Coaching Salespeople, Sales Skills, Customer Focus, Negotiation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.008017518,-0.008637886,0.0383092,0.006180047,-0.03058119,-0.00274439,0.0027635917,0.035922263,0.031408347,0.024672922,0.071324594,-0.057428353,-0.0070544705,-0.029163204,0.010924385,0.018693756,-0.014262556,0.019166417,0.019296398,-0.010723504,0.06437647,0.028336048,0.013128169,0.06711791,-0.0120469555,0.01714579,-0.007113553,0.056057636,-0.030959317,-0.026398135,0.029234104,-0.017902048,-0.063525684,-0.012880022,0.018693756,-0.006245038,-0.0058787256,0.048022393,0.014617052,0.0015509201,-0.0005646087,0.029659498,0.019615445,0.054970514,-0.014723401,0.03783654,-0.0021757192,-0.009707282,0.020608034,0.01421529,-0.030841153,0.02188422,0.0126318745,-0.0008035243,-0.031384714,0.035095103,0.005048614,-0.010617156,-0.042657685,0.0032465926,0.0154560255,-0.054639652,-0.009707282,0.05