	('0e6e8c66-0101-4dc9-8282-5b46430e5af0', 'Virtual Team Building And Management', 'CORP116', 'This corporate training program on Virtual Team Building And Management helps participants understand key principles, explore practical workplace examples, and build confidence applying virtual team building and management in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765257779934-5qml6t335z8.jpg', 'Active', '6 weeks', 2, 0, 0, 9, 9, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:01:37.373857+00', NULL, '["Explain the core concepts and importance of Virtual Team Building And Management in a professional environment.", "Recognize common workplace situations where strong virtual team building and management is critical to success.", "Apply tools, techniques, and best practices related to virtual team building and management in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in virtual team building and management.", "Demonstrate growth in key skills developed in this course: Virtual Team Building And Management, Leadership, People Management, Decision Making, Collaboration, Teamwork, Facilitation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.018101376,0.04131345,0.06180378,0.006738989,-0.05220042,-0.0016461199,0.014119786,0.036488,0.00024940647,0.03950688,0.047517598,-0.042240504,-0.0074402243,-0.057525057,0.016199721,0.01136833,-0.020240737,-0.0021616465,0.029214172,0.007606619,0.050346307,0.015664881,0.0029936205,0.07682685,-0.0493004,0.005580168,-0.032518297,0.057572596,-0.025648568,0.0035804594,0.0145952,-0.019278025,-0.017245632,-0.014999302,0.040790495,0.048420884,-0.0278117,0.019860407,-0.0011424785,0.027360057,0.006013983,-0.022855513,0.037415057,0.08966302,-0.014321838,0.010459101,0.013953391,0.007951294,-0.0025152355,8.811867e-05,-0.