	('33ba132c-ea52-40f6-a802-68850bfbea05', 'Administrative Support', 'CORP003', 'This corporate training program on Administrative Support helps participants understand key principles, explore practical workplace examples, and build confidence applying administrative support in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765168976283-q3voi2m4rvf.webp', 'Active', '3 weeks', 2, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-24 03:34:28.016844+00', NULL, '["Explain the core concepts and importance of Administrative Support in a professional environment.", "Recognize common workplace situations where strong administrative support is critical to success.", "Apply tools, techniques, and best practices related to administrative support in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in administrative support.", "Demonstrate growth in key skills developed in this course: Administrative Support, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.011669881,0.006389129,0.07553216,0.008605884,0.00048310173,0.022132732,0.04486898,0.019532979,0.00031553942,0.045588557,0.035189535,-0.031614874,-0.0028942581,-0.03690723,0.0021833878,0.023954881,-0.032195177,0.014472742,0.02481373,0.025579728,0.06643302,0.030082876,-0.0012984265,0.060119327,0.0059887203,-0.017734041,-0.0133701665,0.0143798925,0.00546935,-0.0021108498,0.015749406,-0.011907805,-0.019091949,0.009969595,0.04930249,0.033587903,0.014310257,-0.006557417,0.022248793,0.011867183,0.022898732,0.032868326,0.022388065,0.04354589,-0.03203269,0.016422557,0.004070821,0.004564078,-0.007996567,0.007282795,-0.02880621,0.030384632,0.019904371,0.0026302205,-0.006638659,0.008513036,-0.0013898242,-0.010944502,-0.053155698,-0.01832595,0.035653777,-0.06847568,0.006998447,0.03888026,-0.009458928,0.014635226,