	('a9944826-ab28-4ee6-98fc-4199ac544ed2', 'Cyber Security', 'CORP126', 'This corporate training program on Cyber Security helps participants understand key principles, explore practical workplace examples, and build confidence applying cyber security in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765251562749-r6fc4o025wb.jpg', 'Active', '4 weeks', 7, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-28 06:25:06.881608+00', NULL, '["Explain the core concepts and importance of Cyber Security in a professional environment.", "Recognize common workplace situations where strong cyber security is critical to success.", "Apply tools, techniques, and best practices related to cyber security in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in cyber security.", "Demonstrate growth in key skills developed in this course: Cyber Security, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'technical', NULL, '[0.0060014813,0.017274534,0.061358776,0.011041336,0.0038030623,-0.007015245,0.004005815,0.056075618,0.020703953,0.08286215,0.0515803,-0.04717767,0.0046893815,-0.043771423,0.013613399,-0.00937297,-0.03167577,0.031606257,0.016776342,0.007849428,0.04270552,0.020240517,0.0013779945,0.079849824,-0.027875606,-0.003423625,0.016822685,0.0316526,0.020970426,0.00641278,0.026415786,-0.03695893,-0.050838802,-0.011035542,0.043122612,0.0067024264,-0.013509126,0.018966071,0.004457664,0.029984236,0.0049355812,0.018189818,0.0200088,0.055890244,-0.03751505,-0.025743807,-0.0018986347,-0.022569278,0.008567752,0.029543972,-0.038859013,0.0043736664,0.014505511,0.026971908,-0.03406246,0.017633697,-0.028617103,-0.0006853767,-0.059087943,0.006899386,0.05626099,-0.05320232,-0.009390349,0.04601908,0.053109635,0.0029239843,-0.009691581,-0.012257852,-0.04068958,-0.04511538,0.08879412,0.03515