	('71a8c1e0-4087-45f1-8f8a-b7bb8978322f', 'BlockChain Basics', 'BSC11234', 'This course provides a foundational introduction to blockchain technology, covering core concepts, underlying architecture, and practical applications. Learners will explore how decentralized systems work, understand key components such as blocks, hashing, and consensus mechanisms, and examine real-world use cases including cryptocurrencies, supply chain tracking, and smart contracts. The course is designed for beginners with no prior technical experience.', 'data:image/jpeg;base64,', 'Active', '8 weeks', 26, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-03 04:27:31.70896+00', '2026-01-29 10:41:22.69084+00', NULL, '["Explain the fundamental principles of blockchain and distributed ledger technology.", "Describe how blocks are created, linked, and validated.", "Compare different consensus mechanisms such as Proof of Work and Proof of Stake.", "Understand the role of cryptography in securing blockchain networks."]', NULL, NULL, NULL, 'pending', NULL, NULL, NULL, NULL, NULL, 'technical', NULL, '[-0.038400315,-0.005168657,0.036113817,0.015919996,-0.012949688,-0.051585063,-0.019467272,0.0049950327,0.0007118589,0.06756917,0.040088475,0.007949314,-0.040344905,-0.04414861,0.046328258,0.019990815,-0.024232585,0.017576104,0.06415011,0.013323648,0.020738734,-0.003712885,0.03224601,0.025493363,-0.01206287,-0.035686437,0.027865337,0.013366386,-0.06269701,0.0148729095,0.03361363,-0.008237797,0.016272588,-0.007901234,0.04038764,0.0058925357,-0.0042925226,0.01876209,0.052738994,0.022266626,-0.023676988,-0.042759616,-0.028976532,-0.009952669,-0.019029204,0.022287995,-0.032053683,0.01241546,0.002522892,0.0676119,-0.062953435,0.004297865,0.011656856,0.019435218,-0.07282597,0.0082057435,-0.014541688,-0.009808428,-0.037951563,0.009771031,0.023612881,-0.00027846638,-0.0031839993,0.047439452,0.017586788,0.030173201,-0.04160568,-0.022480318,-0.026241284,-0.009268858,0.03722501,-0.014573742,-0.0153857