	('e2b3e9a7-2ad3-48a5-8bd8-889011eb732e', 'Administrative Office Procedures', 'CORP002', 'This corporate training program on Administrative Office Procedures helps participants understand key principles, explore practical workplace examples, and build confidence applying administrative office procedures in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765168887939-p0zspmqnzz8.webp', 'Active', '3 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:55:37.118832+00', NULL, '["Explain the core concepts and importance of Administrative Office Procedures in a professional environment.", "Recognize common workplace situations where strong administrative office procedures is critical to success.", "Apply tools, techniques, and best practices related to administrative office procedures in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in administrative office procedures.", "Demonstrate growth in key skills developed in this course: Administrative Office Procedures, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.016372913,0.017697193,0.08716168,0.015975628,-0.009757534,0.0048276014,0.031253003,0.023174895,0.013074253,0.035972252,0.026726373,-0.05162283,0.0047583776,-0.057401504,0.0036447789,-0.014314259,-0.016252523,-0.00044619196,0.026557827,0.018419527,0.056871794,0.013784547,-0.010889191,0.06963304,-0.016336797,-0.010654432,-0.0035063315,0.030289888,0.004490512,-0.0098538445,0.016998935,-0.012845513,-0.003036814,0.0003596623,0.039463535,-0.0022663241,-0.0064648925,0.011924537,0.026702294,0.024198202,0.014783777,0.015217178,0.027183851,0.010359479,-0.033275537,0.041534226,-0.0036146815,0.007572472,0.013375225,0.022067316,-0.024113929,0.039728392,0.028315507,0.013916976,-0.016854469,0.0040240046,-0.005561975,-0.05711257,-0.01807