	('036491b4-ceea-44d1-85c7-1521068fea26', 'Anger Management', 'CORP054', 'This corporate training program on Anger Management helps participants understand key principles, explore practical workplace examples, and build confidence applying anger management in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765169763386-rh53qlzfzb.webp', 'Active', '4 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:55:44.119032+00', NULL, '["Explain the core concepts and importance of Anger Management in a professional environment.", "Recognize common workplace situations where strong anger management is critical to success.", "Apply tools, techniques, and best practices related to anger management in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in anger management.", "Demonstrate growth in key skills developed in this course: Anger Management, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.015883446,0.045079675,0.0337042,0.013598414,-0.04393716,-0.006786789,-0.019124711,0.0036448718,0.03047535,0.05106546,0.061199073,-0.015076233,-0.017448194,-0.0151010705,0.020441087,0.0070351614,0.018627966,0.015486049,-0.00815284,-0.0013450943,0.025756266,0.061894517,-0.0031232887,0.06860059,-0.034821875,0.022564676,-0.059013393,0.03047535,-0.0073828837,-0.008761353,0.03971482,-0.018565873,-0.017348845,-0.0061937985,0.032164287,0.052307326,-0.016914193,0.017696567,0.0025535836,-0.011574175,-0.019832574,-0.01749787,0.031617865,0.0494262,-0.022912396,0.007649884,0.00815284,0.048010476,0.00850677,0.0029075148,-0.01995676,0.0056784246,0.0054797265,0.009636867,-0.026476547,0.039938357,-0.029432185,0.0153742805,0.011599013,-0.0058429716,0.013747438,-0.04897913,0.015597816,0.07639949,-0.014492556,0.02774325,