	('80d7700d-551c-430f-a900-ae21a692661d', 'Body Language Basics', 'CORP074', 'This corporate training program on Body Language Basics helps participants understand key principles, explore practical workplace examples, and build confidence applying body language basics in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765257874269-o5b578xshk.jpg', 'Active', '5 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:55:57.387887+00', NULL, '["Explain the core concepts and importance of Body Language Basics in a professional environment.", "Recognize common workplace situations where strong body language basics is critical to success.", "Apply tools, techniques, and best practices related to body language basics in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in body language basics.", "Demonstrate growth in key skills developed in this course: Body Language Basics, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.0095310025,0.049768385,0.032909047,0.026193887,-0.040433835,-0.0076736184,0.008274887,0.033432923,0.020109762,0.042219784,0.026003385,-0.039981395,0.0062389076,-0.031337414,0.03067066,0.027098767,0.01265641,0.022621993,0.01378751,0.002059792,0.036719065,0.0012390006,-0.02767027,0.07405726,-0.018907223,-0.0051971055,0.014144699,0.03386155,-0.021764738,8.6041706e-05,0.015001954,-0.025622385,0.011066917,0.010376351,0.0011415177,0.011471732,-0.014728108,0.03674288,0.04148159,-0.029289529,-0.0095845815,9.8878205e-05,0.033766303,0.02091939,-0.041791156,0.0018052945,0.020014511,0.029575279,0.022526743,0.031051662,-0.047601435,0.0036135658,0.039338455,0.058198053,-0.027265456,0.04572024,-0.017085558,-0.0008155824,-0.03048016,0.006971146,0.047863375,-0.0216933,-0.0038427622,0.062912956,-0.013418414,0.025217569,-0.027956022,-0.