	('bf81828a-9716-4cf0-8b3d-8ab6b2d46e05', 'Call Center Training', 'CORP075', 'This corporate training program on Call Center Training helps participants understand key principles, explore practical workplace examples, and build confidence applying call center training in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765254761711-8cev5kg6fs2.jpg', 'Active', '3 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:56:20.729628+00', NULL, '["Explain the core concepts and importance of Call Center Training in a professional environment.", "Recognize common workplace situations where strong call center training is critical to success.", "Apply tools, techniques, and best practices related to call center training in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in call center training.", "Demonstrate growth in key skills developed in this course: Call Center Training, Sales Skills, Customer Focus, Negotiation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.027982336,0.013690531,0.07238406,0.012522673,-0.022316491,-0.016650645,0.024767835,0.0567047,0.023264652,0.058554772,0.07326284,-0.022617128,-0.0057265502,-0.020408604,0.0060647666,0.0045442386,0.0067122914,0.0076373275,0.022362743,0.0139102265,0.0235306,0.02412031,0.0009893548,0.065168776,-0.02569287,0.0049287067,-0.013736783,0.027357936,-0.026964795,-0.021981165,0.05314331,-0.01988827,-0.05878603,-0.03642329,0.030133044,0.019980775,-0.002004726,0.016014684,-0.016835652,0.009065351,-0.020281412,0.024282191,0.024143437,0.07192154,-0.021229573,0.006006952,-0.005853743,0.023565289,-0.002808351,0.040054053,-0.05083072,0.022987142,0.024074059,-0.008880344,-0.032144997,0.016835652,-0.022779008,-0.026178515,-0.012256726,0.002357396,0.03172873,-0.051755756,-0.009250359,0.058184758,