	('06163808-6eb0-4a6d-8f8c-72b3a1fa7cb1', 'Basic Bookkeeping', 'CORP005', 'This corporate training program on Basic Bookkeeping helps participants understand key principles, explore practical workplace examples, and build confidence applying basic bookkeeping in their daily roles.', 'data:image/jpeg;base64,', 'Active', '2 weeks', 1, 0, 0, 5, 5, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-23 18:41:00.999873+00', NULL, '["Explain the core concepts and importance of Basic Bookkeeping in a professional environment.", "Recognize common workplace situations where strong basic bookkeeping is critical to success.", "Apply tools, techniques, and best practices related to basic bookkeeping in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in basic bookkeeping.", "Demonstrate growth in key skills developed in this course: Basic Bookkeeping, Numeracy, Financial Literacy, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'technical', NULL, '[-0.028853633,0.03293783,0.07620627,-0.008762999,-0.005354499,-0.0041292408,0.024288945,0.057659216,-0.0034145068,0.027700448,0.062127806,-0.03116,0.0023589225,-0.011519831,0.066212,0.0459592,-0.035292245,0.031039879,0.004744873,0.026234943,0.046848115,0.016673123,0.0060482114,0.07947362,-0.01305741,-0.03716617,-0.030102916,-0.029742546,0.019964503,-0.023736378,0.028709484,-0.021958552,-0.017874356,-0.015555976,0.043052215,-0.00449862,0.011039337,-0.0023514149,0.048866186,-0.019315837,-0.016925381,-0.031760618,0.037598614,0.030102916,-0.017201666,0.023484118,0.043917105,-0.01891943,0.015435853,0.02410876,-0.050932307,0.023976624,0.0011742059,-0.012138466,0.0005619521,0.049634974,-0.035772737,-0.01305741,-0.004390509,0.010342622,0.063617334,-0.028301066,0.016024457,0.046920188,-0.0145709645,0.028445214,-0.029310102,0.034355283,-0.045911152,-0.044349547,0.022643255,0.021357935,-0.004675802,0.0044415616,0