	('a4d7a30b-591f-45fb-bb7e-c9346243a55a', 'Attention Management', 'CORP055', 'This corporate training program on Attention Management helps participants understand key principles, explore practical workplace examples, and build confidence applying attention management in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256546154-tcb3ysb67l.jpg', 'Active', '5 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:55:49.655403+00', NULL, '["Explain the core concepts and importance of Attention Management in a professional environment.", "Recognize common workplace situations where strong attention management is critical to success.", "Apply tools, techniques, and best practices related to attention management in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in attention management.", "Demonstrate growth in key skills developed in this course: Attention Management, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.0072825323,0.057402007,0.04914763,0.019058274,-0.029634984,-0.027161196,0.014123317,0.04260976,0.008046126,0.04420005,0.04356898,-0.034961205,-0.003603402,-0.02023206,0.015372833,-0.008948553,-0.0017370165,-0.031957317,0.04677481,0.010614575,0.01103108,0.08244281,0.005136899,0.09107583,-0.03425441,0.0062412694,-0.03748548,0.041574806,0.00051629305,-0.0062538907,0.054372877,-0.016369922,-0.020661188,0.0087529225,0.039101016,0.051343746,-0.00084405433,0.030543724,-0.012741277,-0.008891758,-0.045310732,0.011939819,0.030745666,0.045462187,-0.013214578,-0.007232047,0.01894468,0.054827247,0.025406824,0.04639617,-0.050561223,0.024788378,-0.023084491,0.042534027,-0.0027987896,0.015814582,-0.010242244,0.07083115,-0.00091189425,0.025558282,0.052000057,-0.019537887,0.027438866,0.065