	('f1cac1d9-b949-4927-9867-dce223662278', 'Generative AI', 'BSC11326', 'This course provides a foundational understanding of Generative Artificial Intelligence, focusing on how machines can create new content such as text, images, audio, and code. Learners will explore key GenAI models, including neural networks, transformers, and diffusion models, while discovering real-world applications across industries. No prior AI experience required.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765195750350-stzkofn8qn8.jpg', 'Active', '8 weeks', 1, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-03 15:13:38.871281+00', '2026-01-19 05:58:40.637179+00', NULL, '["Explain fundamental concepts behind generative AI models", "Understand how neural networks learn patterns and generate data", "Recognize the role of large language models (LLMs)", "Describe how AI can generate images, text, and multimedia"]', NULL, NULL, NULL, 'pending', NULL, NULL, NULL, NULL, NULL, 'technical', NULL, '[-0.0032635198,0.020302497,0.043005746,-0.016228147,-0.023418857,-0.07760887,-0.024907783,0.015362493,-0.021722171,0.0244461,0.03160218,-0.032733306,-0.03838892,-0.030055545,-0.022010723,-0.021064274,-0.016839877,-0.04369827,0.052031644,0.016828336,0.027585542,0.013735061,-0.011276601,0.03838892,-0.000518311,-0.025992738,0.025646476,0.08194868,-0.024469184,0.0012234593,-0.0035953543,-0.007444634,-0.03176377,-0.0077504986,0.01852502,0.0152124455,0.0053006946,0.032179285,0.004097434,0.026985355,0.018224925,-0.014450669,0.016551325,0.021456705,-0.035988167,0.031186668,0.01987544,-0.014993146,-0.013354173,0.06828287,-0.053555194,0.0064981845,0.0068906145,-0.0017471806,-0.07216101,0.029963208,-0.036426768,-0.015154735,-0.026662176,-0.023915164,0.0382735,-0.025046287,0.018917449,0.039104525,-0.0019087695,-0.00998966,-0.020187076,0.0059961043,-0.027377786,-0.019332964,0.002533484,-0.03603434,-0.038134992,-0.020671844,-0.046399113,0.030078629,0.00931444