	('d9d93354-99da-4fd5-bd88-194f969e432d', 'Business Etiquette', 'CORP120', 'This corporate training program on Business Etiquette helps participants understand key principles, explore practical workplace examples, and build confidence applying business etiquette in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765257923828-8somdz2zv3q.jpg', 'Active', '4 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:56:13.662069+00', NULL, '["Explain the core concepts and importance of Business Etiquette in a professional environment.", "Recognize common workplace situations where strong business etiquette is critical to success.", "Apply tools, techniques, and best practices related to business etiquette in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in business etiquette.", "Demonstrate growth in key skills developed in this course: Business Etiquette, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.022423074,0.013758506,0.037509903,0.009127654,-0.027078299,-0.010620494,-0.013490404,0.08900986,0.019705495,0.037924245,0.049915712,-0.041653298,0.0074702958,-0.060054842,0.017572867,0.03304966,-0.006556312,0.013490404,0.009170306,0.04189703,0.0529867,0.020814463,-0.0053864126,0.07838327,-0.031587288,0.025445314,-0.025542807,0.024202297,0.0028851428,0.006556312,0.037339292,-0.010212248,-0.0018782371,-0.03304966,0.015732711,0.017036662,0.003726008,0.00085686,0.020704785,-0.013002946,-0.025420941,0.0013526963,0.041141465,-0.010821571,-0.024385093,0.021740632,-0.0060719005,0.019059613,0.049769476,0.004009343,-0.021533463,0.027590131,-0.008944857,-0.021935616,-0.01563522,-0.022825228,-0.021192243,-0.025835281,-0.019973597,-0.0008705698,0.06736671,-0.033756476,-0.023239566,0.058982436,0.004609526,0.027565759,-0.014952779,0.008548797,0.00