	('3fc30b38-f9ff-41f4-8ad0-7921235fff38', 'Contact Center Training', 'CORP077', 'This corporate training program on Contact Center Training helps participants understand key principles, explore practical workplace examples, and build confidence applying contact center training in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765254804466-e0ayupl8bsf.jpg', 'Active', '6 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:56:37.338392+00', NULL, '["Explain the core concepts and importance of Contact Center Training in a professional environment.", "Recognize common workplace situations where strong contact center training is critical to success.", "Apply tools, techniques, and best practices related to contact center training in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in contact center training.", "Demonstrate growth in key skills developed in this course: Contact Center Training, Sales Skills, Customer Focus, Negotiation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.015279555,0.018930318,0.07422831,0.019688465,-0.022207841,-0.012818497,0.018697042,0.0637309,0.013716607,0.04373918,0.07553465,-0.016154338,-0.0024800117,-0.015559485,0.013448341,0.021729626,0.0016081439,0.0045051356,0.014731357,0.009447663,0.03132892,0.021321394,0.005292441,0.06452404,-0.03676424,0.013040109,-0.0111155845,0.027176613,-0.014253141,-0.031235607,0.052347053,-0.021484686,-0.070402585,-0.036530964,0.046748437,0.026150199,-0.0045372113,0.048707955,-0.019221913,0.0005944884,-0.011739597,0.034804724,0.020411618,0.064244114,-0.055286326,-0.0080013545,-0.005409079,0.013938219,0.009091918,0.033008505,-0.036810897,0.022872677,0.014113177,-0.0055257166,-0.04077658,-0.0058727143,-0.03256528,-0.019198585,-0.027409887,0.0066191964,0.03293852,-0.0516