	('3d005d08-642b-4df2-922c-d836b28988c8', 'Employee Termination Processes', 'CORP037', 'This corporate training program on Employee Termination Processes helps participants understand key principles, explore practical workplace examples, and build confidence applying employee termination processes in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256108753-p3ebq9560h.jpg', 'Active', '3 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:57:51.718678+00', NULL, '["Explain the core concepts and importance of Employee Termination Processes in a professional environment.", "Recognize common workplace situations where strong employee termination processes is critical to success.", "Apply tools, techniques, and best practices related to employee termination processes in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in employee termination processes.", "Demonstrate growth in key skills developed in this course: Employee Termination Processes, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.008080647,0.07280938,0.048507757,0.007018347,-0.029887654,0.0015651033,0.03131997,0.064167745,0.0532344,0.052422754,0.07973224,-0.060252745,-0.03864865,-0.014824467,0.017784586,-0.010825919,0.016423887,0.033850394,-0.011637565,0.02229638,0.031892896,0.04361401,-0.03377878,0.086034425,0.0010697608,0.0053294078,0.017366828,0.03848155,-0.03862478,-0.030054757,0.045165688,-0.0097278105,-0.053664092,-0.031510945,0.036834385,-0.0031600464,-0.031176738,0.048865836,0.006672204,0.022606716,-0.014836404,0.0067378515,0.003980644,0.056051288,-0.026497839,0.03788475,-0.018548489,-0.008534214,0.032871645,-0.010288801,-0.023430297,0.013762167,0.017629419,0.021222144,-0.06326061,-0.0014494737,-0.011834508,-0.027190126,-0.022356061,-0.031749666,0.047648367