	('94f923dc-68ce-47f9-9792-bdf265c0e82c', 'Appreciative Inquiry', 'CORP117', 'This corporate training program on Appreciative Inquiry helps participants understand key principles, explore practical workplace examples, and build confidence applying appreciative inquiry in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765191447256-4h66i7zs2yh.gif', 'Active', '3 weeks', 1, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:55:45.836688+00', NULL, '["Explain the core concepts and importance of Appreciative Inquiry in a professional environment.", "Recognize common workplace situations where strong appreciative inquiry is critical to success.", "Apply tools, techniques, and best practices related to appreciative inquiry in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in appreciative inquiry.", "Demonstrate growth in key skills developed in this course: Appreciative Inquiry, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.015177071,0.01060299,0.0046079857,0.016434634,-0.016323673,-0.04781209,-0.02579239,0.04411337,0.009400907,0.03457068,0.07634153,-0.04036534,0.0113920495,-0.042337988,0.028849997,0.021958053,0.0037726918,-0.0070337276,0.034225468,0.02160051,0.032376107,0.025693757,-0.058193155,0.08600751,-0.010547509,-0.01661957,-0.0484532,0.04071055,0.006780982,-0.0018925105,0.018777156,-0.015127755,-0.062730245,0.0023286508,0.0151524125,0.044409268,-0.008870757,-0.0040901653,0.023782754,-0.020010062,-0.00069774763,0.010917381,0.043447603,0.04463119,-0.05617119,-0.019553887,-0.0014039716,0.051140934,-0.013709913,0.03676525,-0.013500319,0.017741514,-0.008032382,-0.043102387,-0.01099752,0.008685822,-0.024460852,0.0076810033,-0.038442004,-0.011576986,0.070472896,-0.016175725,-0.007083044,0.044261318,-0.008741302,0.0020466237,-0.02135392