	('e01a40e5-214b-47ab-9c94-9926997e69b7', 'Budgets And Financial Reports', 'CORP099', 'This corporate training program on Budgets And Financial Reports helps participants understand key principles, explore practical workplace examples, and build confidence applying budgets and financial reports in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765258023914-96pii49q7ji.jpg', 'Active', '4 weeks', 0, 0, 0, 5, 5, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:55:59.18317+00', NULL, '["Explain the core concepts and importance of Budgets And Financial Reports in a professional environment.", "Recognize common workplace situations where strong budgets and financial reports is critical to success.", "Apply tools, techniques, and best practices related to budgets and financial reports in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in budgets and financial reports.", "Demonstrate growth in key skills developed in this course: Budgets And Financial Reports, Numeracy, Financial Literacy, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'technical', NULL, '[-0.032801528,0.04748566,0.07469655,-0.036629144,0.008832519,-0.0019689035,-0.0029200085,0.046557754,-0.0016209382,0.015310472,0.008327968,-0.04047996,-0.00851355,-0.03215199,0.05019979,0.03458775,-0.013408262,0.018070996,0.0025879918,0.040340774,0.048158392,0.018476956,-0.031572048,0.025123093,-0.023267278,-0.018697334,-0.01172643,-0.0035231484,-0.010438958,0.005660235,0.012097592,-0.015786024,-0.06189142,-0.008490353,0.06472154,0.010566546,-0.021457858,0.020065997,0.061102703,-0.008148187,-0.014834919,0.042521358,0.0050049005,0.03867054,-0.01753745,0.0075566457,0.021133091,-0.016354367,0.026398966,0.051452465,-0.06054596,0.0410831,0.0075102504,-0.027442861,-0.010456356,0.033938214,-0.0035811425,-0.020703934,0.00862