	('009ae85a-b86e-418a-82a1-ce3232b0b0a8', 'Networking Outside the Company', 'CORP130', 'This corporate training program on Networking Outside the Company helps participants understand key principles, explore practical workplace examples, and build confidence applying networking outside the company in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765211811708-g4rgvwabgqo.jpg', 'Active', '6 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:00.764923+00', NULL, '["Explain the core concepts and importance of Networking Outside the Company in a professional environment.", "Recognize common workplace situations where strong networking outside the company is critical to success.", "Apply tools, techniques, and best practices related to networking outside the company in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in networking outside the company.", "Demonstrate growth in key skills developed in this course: Networking Outside the Company, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.02742871,0.009447236,0.062005978,0.019114625,0.0033314617,-0.0019409244,0.017379286,0.0493924,-0.0032278593,0.07164099,0.056877665,-0.01436187,0.02116077,-0.011959591,0.021834185,0.0038170975,-0.0154885445,0.008579566,0.02110897,0.02872374,0.04848588,0.054598413,0.0038915616,0.05167165,0.016019506,-0.005257817,-0.003010942,0.084176876,0.024631448,-0.018570714,0.0358723,-0.021847136,-0.039860986,-0.0029186711,0.036934223,0.026651694,-0.0014852362,0.028620137,0.02742871,0.026625792,-0.003668169,-0.021873036,0.030433178,0.039239373,-0.01662817,0.006151387,-0.025201261,0.016498666,0.074282855,0.010904143,-0.04988451,-0.005316093,-0.0038462356,-0.024877504,-0.077701725,-0.007316913,-0.006649973,-0.017353386,-0.024838652,0.042554647,0.03548379,