	('d8aa8e94-3e76-4d51-bb77-74687cbe0c96', 'Developing New Managers', 'CORP102', 'This corporate training program on Developing New Managers helps participants understand key principles, explore practical workplace examples, and build confidence applying developing new managers in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765253280377-byd7cwrtq4e.jpg', 'Active', '6 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:57:07.041294+00', NULL, '["Explain the core concepts and importance of Developing New Managers in a professional environment.", "Recognize common workplace situations where strong developing new managers is critical to success.", "Apply tools, techniques, and best practices related to developing new managers in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in developing new managers.", "Demonstrate growth in key skills developed in this course: Developing New Managers, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.018505497,0.056305252,0.079409815,-0.0072201774,-0.012334975,0.0029123405,0.055091776,0.05149989,0.019282121,0.05581986,0.06712945,-0.024851972,-0.019209312,-0.04802935,0.025191745,0.0046051387,-0.026599377,-0.015229114,0.014513164,0.03730223,0.08135138,0.03722942,0.042447362,0.07970105,0.0060734437,0.0347782,-0.032011475,0.03385596,-0.005224011,0.0030943619,0.02034998,-0.01621203,-0.060576685,0.037326496,0.05436369,0.00040765182,0.0053514256,0.043854993,-0.006746922,0.028273974,-0.0072383797,0.008737022,0.020798966,0.007948263,-0.0051481687,-0.014367547,0.015459674,0.022230865,0.020592675,0.020362115,-0.028273974,0.019439872,0.027764313,-0.0008615674,-0.021017391,0.006401082,0.009270951,-0.027254654,-0.039947603,0.015556753,0.05635379,-0.0339530