	('3fcbd700-1804-4a12-83de-b0c484388d92', 'Human Resource Management', 'CORP041', 'This corporate training program on Human Resource Management helps participants understand key principles, explore practical workplace examples, and build confidence applying human resource management in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765258106439-li8j6xih1ne.jpg', 'Active', '3 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:58:54.027438+00', NULL, '["Explain the core concepts and importance of Human Resource Management in a professional environment.", "Recognize common workplace situations where strong human resource management is critical to success.", "Apply tools, techniques, and best practices related to human resource management in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in human resource management.", "Demonstrate growth in key skills developed in this course: Human Resource Management, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.016137976,0.054468546,0.0810352,0.018405579,-0.0050244126,-0.027763763,0.028339298,0.0550671,0.018290473,0.01199413,0.03881402,-0.02601414,-0.01654085,-0.042013988,0.025047243,-0.0121552795,-0.0190732,-0.0034100395,0.030365178,0.028799726,0.04031041,0.033357956,-0.014710651,0.087987654,-0.04657222,0.039734874,-0.03595937,0.04065573,-0.026773846,-0.017956663,0.027947934,-0.0070502926,-0.017035808,-0.0034157948,0.055297315,0.020903397,-0.030687477,0.052903093,-0.00015863158,0.02668176,-0.020581098,-0.008241648,0.02008614,0.037916183,-0.03660397,0.0029668782,0.0023697615,-0.003789892,0.040126238,0.013893393,-0.069662645,0.00050071464,-0.0006582671,0.036811158,-0.037778057,0.029444324,0.01621855,0.0048834067,-0.025277456,-0.016022868,