	('3151dec0-2781-499a-8242-075956eaf22e', 'Crisis Management', 'CORP032', 'This corporate training program on Crisis Management helps participants understand key principles, explore practical workplace examples, and build confidence applying crisis management in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765255948287-okiiz6lyuns.jpg', 'Active', '2 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:56:48.715473+00', NULL, '["Explain the core concepts and importance of Crisis Management in a professional environment.", "Recognize common workplace situations where strong crisis management is critical to success.", "Apply tools, techniques, and best practices related to crisis management in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in crisis management.", "Demonstrate growth in key skills developed in this course: Crisis Management, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.044068463,0.061237052,0.06944707,-0.00034277566,-0.031101469,0.00441892,0.017096149,0.04266793,0.013751775,0.04051884,0.04865641,-0.046821233,0.0023000115,-0.013039435,0.020657847,0.015635248,-0.029725084,-0.00019827035,0.025233721,0.01617856,0.030594379,0.0550071,-0.0128824795,0.06712895,-0.024062587,0.042450607,-0.032646883,0.055151984,0.020440523,0.0039661615,0.047473203,-0.009181935,-0.053703155,0.007147542,0.02132189,0.031222204,-0.026561813,0.023748675,0.009900312,0.02359172,-0.03902172,-0.014307158,0.00848167,0.03510989,-0.036534566,-0.026103018,-0.010721314,0.03015973,0.0262479,0.021853128,-0.02111664,0.010099526,-0.0026184514,-0.015768059,-0.023000116,0.017627385,-0.019100359,0.027044754,-0.035592828,0.0048928065,0.06852948,-0.05800134,0.007153579,0.04283696,0.021333965,0.0046513355,0