	('f1db08ef-6389-4008-a4eb-eb1ae0e55bca', 'Interpersonal Skills', 'CORP020', 'This corporate training program on Interpersonal Skills helps participants understand key principles, explore practical workplace examples, and build confidence applying interpersonal skills in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765258126743-ejh2kh7wok8.webp', 'Active', '3 weeks', 1, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:59:04.521695+00', NULL, '["Explain the core concepts and importance of Interpersonal Skills in a professional environment.", "Recognize common workplace situations where strong interpersonal skills is critical to success.", "Apply tools, techniques, and best practices related to interpersonal skills in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in interpersonal skills.", "Demonstrate growth in key skills developed in this course: Interpersonal Skills, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.021300746,0.02650398,0.06067344,0.019012716,-0.023193887,-0.009976739,-0.0018887861,0.05941909,0.023751376,0.04952365,0.042647947,-0.057328507,0.00028146687,-0.042857006,0.040162474,0.005545859,-0.01110914,0.0046922034,0.016492398,0.029570173,0.05519146,0.022798998,-0.023344874,0.053193793,-0.012183469,0.01588845,-0.018106796,0.05565604,-0.011074297,0.0068989326,0.017595762,-0.022136979,-0.03486632,-0.02743313,0.03547027,0.012020867,-0.017073117,0.046968494,0.0086643165,0.0037369218,-0.0058129895,0.012311227,-0.0024985403,0.027224071,-0.015598092,0.02349586,0.00960508,0.0037311148,0.04353064,0.026852412,-0.044784993,0.018687513,-0.013298448,0.0047996365,-0.042113688,0.017526077,-0.022926757,-0.047851183,-0.05049926,-0.009198577,0.05286859,-0.035005696,0.005563281,0.049244907,-0.01609751,0.043762926,0.016713072,-0.00