	('fe1616ee-33b2-48a3-9d15-77a6c72943ba', 'Life Coaching Essentials', 'CORP064', 'This corporate training program on Life Coaching Essentials helps participants understand key principles, explore practical workplace examples, and build confidence applying life coaching essentials in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765258151981-nuc0put8b3n.jpg', 'Active', '3 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:59:15.43727+00', NULL, '["Explain the core concepts and importance of Life Coaching Essentials in a professional environment.", "Recognize common workplace situations where strong life coaching essentials is critical to success.", "Apply tools, techniques, and best practices related to life coaching essentials in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in life coaching essentials.", "Demonstrate growth in key skills developed in this course: Life Coaching Essentials, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.0040760343,0.012928442,0.046650223,0.021543495,-0.020148678,0.0012387803,0.013174586,0.041516356,0.055933386,0.04046145,0.07501543,-0.04709563,0.0017904075,-0.03530414,0.0017156851,0.008011415,-0.008028996,0.038562622,0.021871688,0.009435535,0.052698344,0.012436152,0.0032789952,0.069248624,-0.011410551,-0.0033669039,0.012119682,0.060903158,-0.013866135,-0.01704257,0.03431956,-0.010672118,-0.035163485,0.013022211,0.031998772,0.015600867,0.016468232,0.034553986,0.0320691,-0.0011230338,-0.019093772,0.028201116,0.010425974,0.06409132,-0.029443558,-0.015073414,0.034436774,0.050682303,0.012635413,0.024286248,-0.015073414,-0.004963912,0.0152961165,-0.0019779461,-0.06493524,0.0069916733,-0.038375083,-0.0066283173,-0.036827892,0.024590997,0.032326967,-0.042196184,-0.0013940857,0.05818385,-0.01074