	('742d5c72-bb4e-44fc-b445-7b281bc88513', 'Media And Public Relations', 'CORP085', 'This corporate training program on Media And Public Relations helps participants understand key principles, explore practical workplace examples, and build confidence applying media and public relations in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256906140-mrvh6go958b.jpg', 'Active', '6 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:59:44.825002+00', NULL, '["Explain the core concepts and importance of Media And Public Relations in a professional environment.", "Recognize common workplace situations where strong media and public relations is critical to success.", "Apply tools, techniques, and best practices related to media and public relations in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in media and public relations.", "Demonstrate growth in key skills developed in this course: Media And Public Relations, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.0077439183,0.034032643,0.035035707,-0.0013172722,-0.01009038,0.012586107,0.014042943,0.03962116,-0.0067348806,0.04633216,0.023691494,-0.033292282,0.016419256,-0.024360206,0.025840925,-0.012359222,0.008090216,-0.01167857,0.037806086,0.053496923,0.053879045,0.01887916,-0.0132787,0.047980055,-0.029877076,-0.001719544,-0.0014553432,0.06562926,-0.027297761,0.017398441,0.033101223,-0.019297104,-0.05822567,-0.010460559,0.044278257,0.0015658,-0.02691564,0.015272894,0.0025449847,0.030211432,-0.0056064297,-0.009045518,-0.018234331,0.03188321,-0.009761995,0.020395702,0.011971131,0.060040742,0.06457843,0.05187291,-0.05306704,0.013529467,0.009863495,0.010108291,-0.044851437,0.011302419,0.006693086,-0.017792504,-0.035847716,0.0008269335,0.076042056,-0.032002624,0.029399425,0.03209815