	('b6eb0588-de56-4b71-ba5c-ef06c6797bfe', 'Leadership And Influence', 'CORP106', 'This corporate training program on Leadership And Influence helps participants understand key principles, explore practical workplace examples, and build confidence applying leadership and influence in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765258241110-98setu1ir2n.jpg', 'Active', '3 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:59:09.686317+00', NULL, '["Explain the core concepts and importance of Leadership And Influence in a professional environment.", "Recognize common workplace situations where strong leadership and influence is critical to success.", "Apply tools, techniques, and best practices related to leadership and influence in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in leadership and influence.", "Demonstrate growth in key skills developed in this course: Leadership And Influence, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.01156604,0.0022401258,0.047003645,-0.0065513933,0.0029160632,0.010283492,-0.0034316822,0.04175791,-0.015286584,0.029995443,0.058789223,-0.038430218,-0.004494695,-0.07154537,0.007475752,-0.0064127394,0.0052832887,-0.0040989537,0.026205573,0.030226534,0.042058326,0.028377816,0.035310507,0.08675107,-0.023732914,0.010479919,-0.021468233,0.046564575,-0.026644643,-0.0010904545,0.050238904,-0.005179298,-0.045663327,0.00055100454,-0.0013143227,-0.00042787704,0.021167817,0.03119711,0.033138264,0.002365781,-0.015182594,0.0023137857,0.038522653,0.051948965,0.0013785945,-0.013715174,0.024495509,-0.015459902,0.035564706,0.023594258,-0.0131258955,-0.00932447,-0.0012189982,0.0027254142,-0.06017576,0.017562818,-0.0113985,0.002663309,-0.021733986,0.019561