	('f5e7d242-55d4-4aff-a11d-15c5286ac75f', 'Meeting Management', 'CORP009', 'This corporate training program on Meeting Management helps participants understand key principles, explore practical workplace examples, and build confidence applying meeting management in their daily roles.', 'data:image/png;base64,', 'Active', '5 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:59:46.766962+00', NULL, '["Explain the core concepts and importance of Meeting Management in a professional environment.", "Recognize common workplace situations where strong meeting management is critical to success.", "Apply tools, techniques, and best practices related to meeting management in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in meeting management.", "Demonstrate growth in key skills developed in this course: Meeting Management, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.03375259,0.052817453,0.08258199,-0.018931119,-0.039467186,0.007884926,0.0033922812,0.023332572,0.033582367,0.033582367,0.05967497,-0.038810614,-0.021824893,-0.0325124,0.008742115,-0.008523258,-0.027940726,0.018177278,0.04309048,0.017703088,0.03489551,0.076843075,0.00017411659,0.08924496,-0.023223145,0.029424088,-0.044500895,0.047905333,0.01654801,0.005939532,0.041218042,-0.017362643,-0.01134408,-0.0024849372,0.047491938,0.03414167,0.006517071,0.0044987244,-0.04075601,-0.0022584812,-0.044379305,0.004431851,0.01863931,0.03992922,-0.0034014003,0.009119036,0.00491516,0.03260967,0.030712912,0.014432394,-0.046543557,-0.018043531,0.021776257,0.0019225967,-0.019514736,-0.007593117,0.016377788,0.0007451012,-0.017192421,0.020171307,0.058653638,-0.054811485,0.031539705,0.08350605,0.009070401,0.016876295,0.017228898,-0.02789209,-0.00397286,-0.06804016,0.025022633,0.008213212,-0.01040178,0.0