	('f430edda-89dd-4376-9fbe-7ae001de66b7', 'Recognizing Employee Excellence', 'CORP092', 'This corporate training program on Recognizing Employee Excellence helps participants understand key principles, explore practical workplace examples, and build confidence applying recognizing employee excellence in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765258454629-49dhvkuo93n.jpg', 'Active', '6 weeks', 0, 0, 0, 5, 5, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:31.868143+00', NULL, '["Explain the core concepts and importance of Recognizing Employee Excellence in a professional environment.", "Recognize common workplace situations where strong recognizing employee excellence is critical to success.", "Apply tools, techniques, and best practices related to recognizing employee excellence in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in recognizing employee excellence.", "Demonstrate growth in key skills developed in this course: Recognizing Employee Excellence, MS Office, Digital Literacy, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.009281252,0.026549121,0.039945245,0.02511469,-0.0037319507,0.01043609,0.0052423575,0.0679288,0.0039902697,0.053827614,0.049475696,-0.040455803,0.0024677068,-0.042473733,0.02990423,0.027327118,-0.006041627,-0.019510686,0.002349184,0.017614322,0.049840383,0.023206169,0.030803788,0.10532124,0.005543223,0.0182586,-0.02132196,0.07366652,-0.008867942,-0.026962431,0.018453099,-0.018039787,-0.023668105,-0.020033402,0.020787086,0.013845902,-0.008199351,0.010259826,-0.001002126,0.013165155,-0.010247669,0.024968816,0.02907761,0.0569396,-0.0051876544,-0.03552039,-0.029320734,-0.024300225,0.017492758,0.0329919,-0.010271981,0.012253441,-0.0074091987,0.0036468573,-0.026670683,-0.020361621,-0.0041604564,0.011882677,-0.