	('941461f7-afab-4a9f-a72c-0b10dc7475ca', 'Developing Corporate Behavior', 'CORP128', 'This corporate training program on Developing Corporate Behavior helps participants understand key principles, explore practical workplace examples, and build confidence applying developing corporate behavior in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765250665566-gkly19s27iq.jpg', 'Active', '6 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:57:01.709495+00', NULL, '["Explain the core concepts and importance of Developing Corporate Behavior in a professional environment.", "Recognize common workplace situations where strong developing corporate behavior is critical to success.", "Apply tools, techniques, and best practices related to developing corporate behavior in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in developing corporate behavior.", "Demonstrate growth in key skills developed in this course: Developing Corporate Behavior, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.007578108,0.016251845,0.074600235,0.043070436,0.0023616916,0.009160684,0.0497903,0.061598755,0.02183956,0.06091703,0.06622475,-0.029752443,0.014949263,-0.06267004,0.02795074,0.018503975,0.017347476,-0.019733515,0.014072759,0.028948981,0.045066915,0.0111693395,0.006732038,0.102161415,-0.011887586,-0.0021243049,-0.016677924,0.047526,-0.01739617,-0.014486664,0.006032052,-0.025589049,-0.04053831,-0.0053198924,0.03143241,0.023592567,0.0005208047,0.022996057,0.014170148,0.01812659,-0.028413339,-0.042047847,0.016811835,0.038249664,-0.020488283,0.01030501,-0.0030175478,-0.004702079,0.028900286,0.009818062,-0.046625145,0.0008308528,0.04657645,-0.00025869042,-0.032576732,0.006397262,-0.010645872,-0.011704981,-0.047209483,0.014815353,0.04319217,-0.022229116,