	('21f8d265-50cb-4c79-b0ba-67df9e87549e', 'Handling a Difficult Customer', 'CORP129', 'This corporate training program on Handling a Difficult Customer helps participants understand key principles, explore practical workplace examples, and build confidence applying handling a difficult customer in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765250698625-cpaf99tywc.jpg', 'Active', '2 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:58:45.309594+00', NULL, '["Explain the core concepts and importance of Handling a Difficult Customer in a professional environment.", "Recognize common workplace situations where strong handling a difficult customer is critical to success.", "Apply tools, techniques, and best practices related to handling a difficult customer in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in handling a difficult customer.", "Demonstrate growth in key skills developed in this course: Handling a Difficult Customer, Sales Skills, Customer Focus, Negotiation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.010395653,0.0051522846,0.06825183,0.010869287,-0.019746883,-0.021969318,-0.009478747,0.028418023,0.041461166,0.049282197,0.09574688,-0.032887183,-0.031138381,-0.023487374,0.027252156,0.017026525,0.01745158,0.0036888781,0.010237775,0.010753915,0.038206454,0.061936717,0.027737934,0.049792264,-0.017293703,0.048674975,0.00080912426,0.06509428,0.00828859,-0.02579482,0.050375197,-0.015423457,-0.030652603,-0.009946308,0.030798336,0.025066154,-0.0049336846,0.07568424,-0.004056248,0.012994566,-0.015071268,0.036433365,0.02325663,0.033445828,-0.014294023,0.023195907,0.04277277,0.011191115,0.038837966,0.019346116,-0.018301694,0.04646468,0.009357302,-0.008798657,-0.019831894,-0.0066369446,-0.027665067,-0.0061329496,-0.