	('d608b9b6-6858-4649-9b85-da4fcf967485', 'Leadership Development for Women', 'CORP021', 'This corporate training program on Leadership Development for Women helps participants understand key principles, explore practical workplace examples, and build confidence applying leadership development for women in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765258284296-bfmz95soxu.webp', 'Active', '4 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:59:11.331059+00', NULL, '["Explain the core concepts and importance of Leadership Development for Women in a professional environment.", "Recognize common workplace situations where strong leadership development for women is critical to success.", "Apply tools, techniques, and best practices related to leadership development for women in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in leadership development for women.", "Demonstrate growth in key skills developed in this course: Leadership Development for Women, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.010082034,0.018500589,0.078768,0.010334928,-0.006277387,0.0038467962,0.026997821,0.042396247,0.027335014,0.03558497,0.06415635,-0.018759103,-0.019995473,-0.09081699,0.023131356,0.02996511,0.033269588,0.008834424,0.0131392395,0.02830163,0.04958967,0.030055027,0.010941873,0.06280759,-0.010048315,0.036012083,-0.012127664,0.045903042,-0.017264219,0.012521055,0.03562993,-0.0057659796,-0.042845834,0.016241403,0.015870493,0.01966952,0.01968076,0.04666734,0.03529274,-0.00941327,-0.013397753,-0.012779568,0.015713137,0.023850698,0.012386178,0.015578261,-0.0045801885,0.021344239,0.004953909,-0.007457558,-0.021647712,0.013274116,0.021243082,-0.0018798441,-0.058806248,0.014375609,0.0104136