	('9b4cd229-ef75-4f1e-92e9-e8b7b52d908d', 'Employee Recruitment', 'CORP036', 'This corporate training program on Employee Recruitment helps participants understand key principles, explore practical workplace examples, and build confidence applying employee recruitment in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256089606-008unxd1j9v0d.jpg', 'Active', '3 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:57:49.986386+00', NULL, '["Explain the core concepts and importance of Employee Recruitment in a professional environment.", "Recognize common workplace situations where strong employee recruitment is critical to success.", "Apply tools, techniques, and best practices related to employee recruitment in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in employee recruitment.", "Demonstrate growth in key skills developed in this course: Employee Recruitment, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.0005368108,0.034617424,0.062054582,0.017439477,-0.0037357572,-3.749781e-05,0.010425646,0.060104974,-0.0021962805,0.057014134,0.07793675,-0.073657125,0.0065026544,-0.015002468,0.031716786,-0.007239701,-0.00923686,-0.0123514775,-0.026842767,0.01305286,0.04731365,0.017403815,-0.004945346,0.07299141,-0.011335066,0.00010689779,-0.010074954,0.051545724,-0.032430056,-0.018889796,0.04203544,-0.010063066,-0.06557339,-0.009641048,0.051878583,0.017463254,0.00027026286,0.032667816,-0.018426169,0.005001813,-0.007340748,0.023502281,0.022943553,0.05820292,-0.037327852,-0.010758505,-0.06866423,-0.013920674,0.03773204,0.017189832,-0.08283455,-0.004651122,0.004487664,-0.0010855094,-0.047408752,0.0007181005,-0.001194729,-0.032548938,-0.045673124,0.014586394,0.08388068,-0.02505959,0.00096068694,0.03523559,0.019614954,0.013207403,-0.010