	('f5d5caa4-70cf-4578-a097-d091fb1502ae', 'Generation Gaps', 'CORP038', 'This corporate training program on Generation Gaps helps participants understand key principles, explore practical workplace examples, and build confidence applying generation gaps in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256132472-yt9il4dq3yq.jpg', 'Active', '3 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:58:04.745222+00', NULL, '["Explain the core concepts and importance of Generation Gaps in a professional environment.", "Recognize common workplace situations where strong generation gaps is critical to success.", "Apply tools, techniques, and best practices related to generation gaps in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in generation gaps.", "Demonstrate growth in key skills developed in this course: Generation Gaps, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.008811061,0.05493714,0.084366776,0.012074926,-0.008975626,-0.03063644,0.01616847,0.005828329,0.021173974,0.009174475,0.0575976,-0.047284886,-0.020625427,-0.024904106,0.01053899,-0.013713715,-0.02096827,-0.043472476,0.0051357863,0.04234795,0.037081886,0.054800004,-0.011252102,0.08277598,-0.016291892,0.0090990495,0.0054272027,0.085079886,0.0018787789,0.019665467,0.02665946,-0.022312215,-0.02735886,-0.025315518,0.066703506,0.019007208,-0.01915806,0.09034595,0.021530531,0.05054875,0.0036135637,0.008413364,0.014563965,0.0057083336,0.0054272027,0.005982608,0.0174987,-0.016346747,0.048848253,0.06533214,-0.016785586,-0.011594946,-0.011265816,0.0070557063,-0.061711717,0.040236037,-0.041909114,-0.018102104,-0.027482284,0.022586487,0.04692833,-0.015030231,0.022723624,0.058749553,0.042814218,0.007405406,-0.019020922,0.001447654,-0.037301302,-0.009284185,0.028113116,-0.