	('94f50ba2-a906-423e-8e47-0abf296ae975', 'Hiring Strategies', 'CORP040', 'This corporate training program on Hiring Strategies helps participants understand key principles, explore practical workplace examples, and build confidence applying hiring strategies in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256178134-40qoss4ac5o.jpg', 'Active', '3 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:58:52.166215+00', NULL, '["Explain the core concepts and importance of Hiring Strategies in a professional environment.", "Recognize common workplace situations where strong hiring strategies is critical to success.", "Apply tools, techniques, and best practices related to hiring strategies in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in hiring strategies.", "Demonstrate growth in key skills developed in this course: Hiring Strategies, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.014008554,0.010701145,0.07079772,-0.012438733,0.0035950094,-0.03225922,0.011599897,0.021809723,-0.040120304,0.05296647,0.07400926,-0.05124087,0.0021644952,0.021030806,0.022289058,-0.008789798,-0.019628752,0.006680726,-0.012235016,0.0057999487,0.041102942,0.02418243,-0.002434121,0.080288544,-0.011785639,0.035015393,-0.009179258,0.023774996,-0.06595644,-0.029407177,0.017543646,-0.0189457,-0.04587232,-0.017615546,0.040048406,0.008861698,-0.040839307,0.023882845,0.0019757573,0.012870134,0.0072978693,0.026866704,0.013553185,0.0063871336,0.00045012514,0.031204682,0.0128941005,-0.033649288,0.020611387,0.058574688,-0.08580089,0.0050599757,0.007076177,0.011785639,-0.016980428,0.007639395,-0.024170447,-0.00897554,-0.01591391,0.032666653,0.07055805,-0.040192205,0.0040473817,0.047022723,0.021426257,0.03494349,0.0036908763,0.011659814,-0.050330132,-0.04