	('ee145959-0b35-4286-bb97-6eb4f3dc980f', 'Sensitivity Training', 'CORP045', 'This corporate training program on Sensitivity Training helps participants understand key principles, explore practical workplace examples, and build confidence applying sensitivity training in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256379112-1c7xzljel6g.jpg', 'Active', '2 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:45.849342+00', NULL, '["Explain the core concepts and importance of Sensitivity Training in a professional environment.", "Recognize common workplace situations where strong sensitivity training is critical to success.", "Apply tools, techniques, and best practices related to sensitivity training in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in sensitivity training.", "Demonstrate growth in key skills developed in this course: Sensitivity Training, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.0149869295,0.014605175,0.051918566,0.018176423,-0.03763357,-0.0068838894,0.017092735,0.069159076,0.034062322,0.011822064,0.037239503,-0.0429535,0.007031665,-0.020035936,0.042362396,0.009630056,0.033963803,0.023976624,0.017129678,-0.0073210597,0.05482482,0.023126913,-0.019765014,0.072607175,-0.010005653,-0.026845938,0.0024321433,0.07349383,0.01684644,0.0076104538,0.036870062,-0.025491325,-0.055711478,0.0004102318,0.02441995,0.020454634,-0.031032918,0.042091474,-0.014703692,-0.016267654,-0.015048502,0.034160838,-0.02674742,0.032830857,-0.0012229987,-0.005033613,-0.01022116,0.034333244,-0.0065452363,-0.0073826327,0.0061634826,0.0016009045,0.014876097,0.012302335,-0.0226959,0.01249937,-0.056942943,0.005649346,-0.029752195,0.0010675262,0.03948077,-0.034037694,-0.007444206,0.023878107,0.0040823063,0.026205575,0.008306231,0.