	('b066b886-7922-4759-a369-83a8c1d3bfcf', 'Talent Management', 'CORP046', 'This corporate training program on Talent Management helps participants understand key principles, explore practical workplace examples, and build confidence applying talent management in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256402546-hg41opm8su.jpg', 'Active', '2 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:01:05.697149+00', NULL, '["Explain the core concepts and importance of Talent Management in a professional environment.", "Recognize common workplace situations where strong talent management is critical to success.", "Apply tools, techniques, and best practices related to talent management in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in talent management.", "Demonstrate growth in key skills developed in this course: Talent Management, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.0037878293,0.052129008,0.06606775,-0.0027871595,0.0061864937,-0.010972049,0.016646435,0.045371544,-0.018965635,0.013597336,0.03451722,-0.027924573,0.004379402,-0.056225866,0.035576753,0.029243102,-0.019460084,-0.017753059,0.025475875,0.010618872,0.035812203,0.042499032,-0.01311466,0.0989839,-0.017611787,0.019059816,-0.043464385,0.039602976,-0.03209207,-0.014998274,0.027736211,-0.017588243,-0.040191606,-0.013738607,0.04612499,0.02896056,0.010442283,0.046478167,-0.016057806,-0.022803498,-0.057120584,0.015787037,0.0071165278,0.037130736,-0.008305559,-0.00076080335,0.0031727117,0.0030137817,0.01643453,0.0064925808,-0.04798506,-0.0042940504,-0.020366572,0.027830392,-0.032539427,0.016293257,-0.013926968,0.023074267,0.0032021431,-0.0136091085,0.022909451,-0.024745975,0.004023281,0.048879772,-0.0018895