	('8fda518a-acfb-41e2-b890-81eb4119025c', 'Improving Mindfulness', 'CORP060', 'This corporate training program on Improving Mindfulness helps participants understand key principles, explore practical workplace examples, and build confidence applying improving mindfulness in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256626698-0ls4vlxgr89.jpg', 'Active', '4 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:58:55.746647+00', NULL, '["Explain the core concepts and importance of Improving Mindfulness in a professional environment.", "Recognize common workplace situations where strong improving mindfulness is critical to success.", "Apply tools, techniques, and best practices related to improving mindfulness in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in improving mindfulness.", "Demonstrate growth in key skills developed in this course: Improving Mindfulness, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.0067568743,0.048569098,0.08999707,0.047244914,-0.048167113,-0.015712835,0.034239557,0.064175524,0.044431027,0.07018164,0.08016029,0.0036947036,0.009003254,-0.028777309,0.038755964,0.038188457,-0.012006309,-0.029273877,0.043296017,0.03343559,0.04769419,0.01917699,-0.006579528,0.11596049,-0.018928707,0.0016286254,-0.033790283,0.016457688,-0.0093934145,0.00685737,0.020867687,-0.025301332,-0.0076613375,0.0033932158,0.00013984453,0.062047377,0.014459592,0.015795598,6.946043e-05,-0.01328911,-0.02657822,0.003006011,0.030905457,0.059304427,0.0026971337,-0.009275184,0.020725809,0.021707123,0.021919938,0.032915376,-0.04320143,0.016339457,0.003727217,-0.0008401756,0.0013892086,0.024166318,-0.018089268,0.014731523,-0.031260148,0.046511885,0.054953545,-0.051028293,0.0031715336,0.043603417,-0.015949298,0.002719302,-0.00864