	('4d7dccb4-cb27-4c66-b717-9b3c19d7a57e', 'Workplace Harassment', 'CORP050', 'This corporate training program on Workplace Harassment helps participants understand key principles, explore practical workplace examples, and build confidence applying workplace harassment in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256485785-egzotrtmrbp.jpg', 'Active', '6 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:01:46.538585+00', NULL, '["Explain the core concepts and importance of Workplace Harassment in a professional environment.", "Recognize common workplace situations where strong workplace harassment is critical to success.", "Apply tools, techniques, and best practices related to workplace harassment in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in workplace harassment.", "Demonstrate growth in key skills developed in this course: Workplace Harassment, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.0062533477,0.025295498,0.024942866,0.041845713,-0.032959376,-0.029409543,0.01675004,0.019747414,0.015844949,0.050638013,0.0484752,-0.0022201147,0.0015339509,-0.024519706,-0.0039377282,0.016209336,0.017314252,0.010978622,0.025083918,0.012342134,0.04125799,0.049744677,-0.02152233,0.07198402,-0.035733417,0.017678637,-0.027199712,0.054775566,-0.0008698266,0.040341146,0.025271988,-0.022815317,-0.05609206,0.004014132,0.066576995,-0.018383902,-0.02463725,0.030890597,0.0063767694,0.018771797,-8.7561195e-05,0.010273357,0.028680768,0.028586732,-0.024613742,0.0046341773,0.0007926882,0.024566723,0.010050023,0.023379527,-0.018184077,0.011801431,0.010484937,0.009297741,-0.07193701,0.011589851,-0.025953744,0.024284618,-0.030655509,-0.01670302,0.055762935,-0.019347765,-0.018184077,0.016068283,-0.0032383408,0.0105319545,-0.0030414544