	('b7bca9ea-9d46-427a-9efd-b1d965efa274', 'Managing Personal Finances', 'CORP065', 'This corporate training program on Managing Personal Finances helps participants understand key principles, explore practical workplace examples, and build confidence applying managing personal finances in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256305436-w4ztqhuxmt.jpg', 'Active', '6 weeks', 0, 0, 0, 5, 5, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:59:18.813957+00', NULL, '["Explain the core concepts and importance of Managing Personal Finances in a professional environment.", "Recognize common workplace situations where strong managing personal finances is critical to success.", "Apply tools, techniques, and best practices related to managing personal finances in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in managing personal finances.", "Demonstrate growth in key skills developed in this course: Managing Personal Finances, Numeracy, Financial Literacy, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.009980364,0.04112827,0.087807894,-0.0029702745,0.009008877,0.0020380097,0.022603653,0.068112664,0.019912455,0.043445356,0.05720305,-0.043710854,-0.02903598,-0.030773794,0.04877948,0.0066616214,-0.028963571,0.017040234,0.018138437,0.026598213,0.057637505,0.04257645,-0.0042359224,0.06280268,-0.05290679,0.0082606515,-0.01746262,0.035214875,-0.01192937,0.006317679,0.046317577,-0.022724334,-0.04877948,0.0068547116,0.03960768,0.014493854,0.0051772385,0.042166132,0.028987708,-0.016955758,-0.03634928,0.009732966,0.013250833,0.03864223,0.015881691,9.701665e-05,0.0443384,0.0122733135,0.031159975,0.038087096,-0.034949377,0.018922865,-0.0154472375,0.022108858,-0.008713207,0.029277343,-0.03014625,-0.0278533,-0.032535743,0.0038949968,0.049913887,-0.022784