	('f2eaae66-d564-4008-bf94-13ed8b34e113', 'Managing Workplace Anxiety', 'CORP066', 'This corporate training program on Managing Workplace Anxiety helps participants understand key principles, explore practical workplace examples, and build confidence applying managing workplace anxiety in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256258880-p2brj9vro4.jpg', 'Active', '3 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:59:20.488619+00', NULL, '["Explain the core concepts and importance of Managing Workplace Anxiety in a professional environment.", "Recognize common workplace situations where strong managing workplace anxiety is critical to success.", "Apply tools, techniques, and best practices related to managing workplace anxiety in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in managing workplace anxiety.", "Demonstrate growth in key skills developed in this course: Managing Workplace Anxiety, Emotional Intelligence, Conflict Management, Resilience, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.0074541154,0.033493433,0.07353942,0.03245634,-0.03537906,0.0025603266,0.048649155,0.048036326,0.002937452,0.06057574,0.035096217,-0.029297916,-0.0018870992,-0.038136788,-0.008874228,0.027105875,0.014118626,0.015686052,0.0027798254,8.3554965e-05,0.031466387,0.065054104,-0.009775793,0.061188567,-0.022592157,0.016016036,-0.036746137,0.007819456,0.00031838354,0.027247297,0.024465999,-0.025455952,-0.011649634,0.025243819,0.037641812,0.027577281,-0.0018870992,0.001115171,0.012551199,-0.02207361,-0.016404947,0.03957458,0.033634856,0.06081144,-0.0024365825,-0.016369592,0.024018163,0.024041733,0.039480295,0.0025573804,-0.0017913448,0.014707884,0.032055642,0.012126933,-0.035496913,-0.0046639782,-0.012062115,0.016676005,-0.01