	('f6ceda85-9cd3-47a7-9b21-9390d0c34433', 'Public Speaking', 'CORP068', 'This corporate training program on Public Speaking helps participants understand key principles, explore practical workplace examples, and build confidence applying public speaking in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256870659-002vrv2boawlt.jpg', 'Active', '4 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:29.879435+00', NULL, '["Explain the core concepts and importance of Public Speaking in a professional environment.", "Recognize common workplace situations where strong public speaking is critical to success.", "Apply tools, techniques, and best practices related to public speaking in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in public speaking.", "Demonstrate growth in key skills developed in this course: Public Speaking, Communication, Active Listening, Presentation Skills, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.0064924564,0.016900256,0.071668305,0.014971803,-0.03099549,0.008157938,-0.022498611,0.04258958,0.029896855,0.039457306,0.055212177,-0.028868347,-0.0015895123,-0.059232708,0.022767426,0.013160227,-0.0139900455,0.005160071,0.018641707,0.017683323,0.04233245,0.028260594,-0.007672903,0.08765693,-0.018244328,0.008087813,-0.017098945,0.0519864,0.00525065,0.013148539,0.019728653,-0.016900256,-0.044108965,-0.002847389,0.036067903,0.029195601,-0.011938874,0.02603995,0.00851441,0.009075413,0.004771459,0.0015150039,0.03487577,0.026156828,0.024193311,0.046002354,1.5374204e-05,0.017426196,0.018150827,0.010016265,-0.057689946,0.02648408,0.026834708,0.0013199672,-0.009659793,-0.00805275,0.01265766,0.0011388096,-0.029031975,0.0047480837,0.08826468,-0.04880738,0.02274405,0.054838173,0.0042951894,0.0154509945,-0.014597