	('67973426-e1d4-4ff5-8a9b-9beb7533c6d9', 'Social Intelligence', 'CORP069', 'This corporate training program on Social Intelligence helps participants understand key principles, explore practical workplace examples, and build confidence applying social intelligence in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765253888828-9tgftbdj1aj.jpg', 'Active', '2 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:49.942895+00', NULL, '["Explain the core concepts and importance of Social Intelligence in a professional environment.", "Recognize common workplace situations where strong social intelligence is critical to success.", "Apply tools, techniques, and best practices related to social intelligence in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in social intelligence.", "Demonstrate growth in key skills developed in this course: Social Intelligence, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.0031313759,0.017463788,-0.0012877596,0.02206646,0.008150566,-0.001830881,-0.011129119,0.046506174,-0.008036698,0.012429615,0.02826329,-0.058396414,0.01075755,-0.027975623,0.028215345,0.008839769,-0.00054611795,-0.004045318,0.033129655,0.0009708763,0.033009794,0.045667145,-0.025770174,0.07882077,-0.022042489,0.029198207,-0.010721591,0.04710548,-0.018135011,0.024343826,0.030540653,-0.014838826,-0.02253392,-0.016816538,0.012897073,0.009493013,-0.01312481,0.0145032145,0.03914669,0.022677753,-0.019753138,0.03943436,0.0005933133,0.015186423,-0.008186525,-0.024739368,0.013208712,-0.02098771,0.019525401,0.03475977,-0.025482507,-0.010571765,-0.031715292,-0.0016196255,-0.051204737,0.019225748,-0.052067738,0.00088697346,-0.046386313,0.004896333,0.032602265,-0.017715497,0.001616629,0.07081404,0.016253188,3.3804627e-05,-0.002063112,0.0196