	('2f512973-adc2-4e1a-a4a0-d0b87e905fbb', 'Marketing Basics', 'CORP084', 'This corporate training program on Marketing Basics helps participants understand key principles, explore practical workplace examples, and build confidence applying marketing basics in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765254953147-5sfh3laq44w.jpg', 'Active', '5 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:59:23.842474+00', NULL, '["Explain the core concepts and importance of Marketing Basics in a professional environment.", "Recognize common workplace situations where strong marketing basics is critical to success.", "Apply tools, techniques, and best practices related to marketing basics in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in marketing basics.", "Demonstrate growth in key skills developed in this course: Marketing Basics, Sales Skills, Customer Focus, Negotiation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.046005,0.05787499,0.06578832,-0.008094773,-0.011372482,-0.023927283,0.015779832,0.048088685,0.005001434,0.04633277,0.07047076,-0.049165647,-0.010277961,-0.017875224,0.040971372,0.016002247,-0.035797272,-0.004199566,0.02342392,-0.015861774,0.0715009,0.030084694,0.008463515,0.087140255,-0.05047673,-0.012560653,-0.023283446,0.007486055,-0.017044092,0.026151441,0.044202257,-0.020801751,-0.04783115,0.014679458,0.039402753,-0.017465511,-0.005668682,0.01999403,0.01460922,0.009019555,-0.031091418,0.014913579,0.032004494,0.051366396,0.005124348,0.01539353,0.0051594665,-0.008920053,0.025636373,0.058764655,-0.060965404,-0.012771362,0.028843846,0.0044863652,-0.015779832,0.037084945,0.0022417193,-0.038442854,-0.0041937125,0.023494156,0.034017947,-0.022077717,0.009616567,0.036803998,0.007041223,0.021902125,0.014468747,-