	('7e323125-cd31-4812-a7f3-f9427346754e', 'Prospecting and Lead Generation', 'CORP091', 'This corporate training program on Prospecting and Lead Generation helps participants understand key principles, explore practical workplace examples, and build confidence applying prospecting and lead generation in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765254274754-0a060igyjrdl.jpg', 'Active', '6 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:28.03754+00', NULL, '["Explain the core concepts and importance of Prospecting and Lead Generation in a professional environment.", "Recognize common workplace situations where strong prospecting and lead generation is critical to success.", "Apply tools, techniques, and best practices related to prospecting and lead generation in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in prospecting and lead generation.", "Demonstrate growth in key skills developed in this course: Prospecting and Lead Generation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.031001901,0.0015308129,0.09150075,0.0053456957,-0.042364247,-0.0027496628,0.019413812,0.04650285,0.014748477,0.026436895,0.08126712,-0.052171484,0.005192066,-0.031854704,0.03950485,0.014309534,0.0040100557,-0.0053237486,-0.017168934,0.0038031256,0.07128431,0.043768864,0.0026947951,0.05778995,-0.016742531,0.015174879,-0.004699823,0.077103436,0.017068602,-0.016755072,0.017808534,-0.01591481,-0.05799061,-0.0131432,0.00862209,0.0018796156,0.031026984,0.0375735,0.0060730865,0.0019360512,0.016504249,-0.004298504,0.06054902,0.02154582,0.009700635,0.010660038,-0.031854704,-0.03080124,0.054980718,0.02997352,-0.01970226,-0.022599282,0.03581773,0.021269912,-0.07770541,-0.016642202,-0.01724418,-0.034312785,-0.016040223,0.04740582,0.020254074,