	('54bd7fa5-986c-4f18-88d4-69820788aaa2', 'Stress Management', 'CORP071', 'This corporate training program on Stress Management helps participants understand key principles, explore practical workplace examples, and build confidence applying stress management in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765254823023-98kkbvgxm7g.jpg', 'Active', '2 weeks', 0, 0, 0, 9, 9, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:57.829857+00', NULL, '["Explain the core concepts and importance of Stress Management in a professional environment.", "Recognize common workplace situations where strong stress management is critical to success.", "Apply tools, techniques, and best practices related to stress management in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in stress management.", "Demonstrate growth in key skills developed in this course: Stress Management, Leadership, People Management, Decision Making, Emotional Intelligence, Conflict Management, Resilience, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.0010007191,0.049496487,0.066993356,-0.009216265,-0.031063959,-0.008011601,0.019941283,0.04156676,0.0125027755,0.036022965,0.047578383,-0.012420905,-0.022514353,-0.040350396,0.010461864,0.015988113,-0.0019868186,0.0054034446,0.011806877,0.02139156,0.04652576,0.03475982,-0.010572974,0.040748052,-0.02940316,0.035742264,-0.015450109,0.03185927,-0.007900491,-0.01804657,0.042432245,-0.023976324,-0.006894655,0.0059531457,0.045169055,0.05688821,-0.010765954,0.040139873,0.002416638,-0.0018435454,-0.017777566,0.0015657708,0.01790622,0.064747766,-0.0038596033,0.01585946,0.0003921737,0.042408854,0.04023344,0.021555299,-0.028982112,-0.01950854,0.02774236,0.00090496003,-0.03976561,0.0135553945,-0.015415021,0.0028698489,-0.034549296,0.02135647,0.0708763