	('9eaf189f-c051-4af0-af99-735bda75c568', 'Taking Initiative', 'CORP072', 'This corporate training program on Taking Initiative helps participants understand key principles, explore practical workplace examples, and build confidence applying taking initiative in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765254873877-7wpwbg7rm9l.jpg', 'Active', '3 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:01:03.510649+00', NULL, '["Explain the core concepts and importance of Taking Initiative in a professional environment.", "Recognize common workplace situations where strong taking initiative is critical to success.", "Apply tools, techniques, and best practices related to taking initiative in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in taking initiative.", "Demonstrate growth in key skills developed in this course: Taking Initiative, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.0071126646,0.02828566,0.06840415,0.025244951,-0.022876028,-0.018762821,0.03528636,0.05572275,0.0033029402,0.050348476,0.08952411,-0.017183539,-0.027507804,-0.060107026,0.036512073,-0.0071244505,-0.022274958,-0.034154933,0.021296745,0.022039244,0.06543416,0.032080654,-0.022557814,0.10069695,-0.028686373,-0.02453781,-0.026470663,0.031727083,-0.026659233,-0.028332803,0.02451424,-0.018880678,-0.056995604,0.014684971,0.033824936,0.023052813,0.0040807957,0.017513538,0.018126393,0.007937663,-0.023913167,0.019304963,0.061474167,0.0022584333,-0.033494934,-0.023453526,0.005386061,-0.010000159,0.03750207,0.035946358,-0.019953176,0.011396764,0.02538638,-0.002105219,-0.051857043,-0.03580493,-0.018456394,0.011137479,-0.055769894,-0.00398651,0.03476779,-0.03783207,-0.005916417,0.03153851,0.024278525,0.012268905,-0.008915876,-0.0020182997,0.0064998087,-0.0