	('ad6b7552-3bb7-4fdc-b455-293cc1def22a', 'Multi-Level Marketing', 'CORP087', 'This corporate training program on Multi-Level Marketing helps participants understand key principles, explore practical workplace examples, and build confidence applying multi-level marketing in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765254294148-w9pl9f46p2n.jpg', 'Active', '4 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:59:56.827869+00', NULL, '["Explain the core concepts and importance of Multi-Level Marketing in a professional environment.", "Recognize common workplace situations where strong multi-level marketing is critical to success.", "Apply tools, techniques, and best practices related to multi-level marketing in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in multi-level marketing.", "Demonstrate growth in key skills developed in this course: Multi-Level Marketing, Sales Skills, Customer Focus, Negotiation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.03924802,0.057192106,0.043080736,0.0012451664,-0.007472554,0.013800271,0.032030564,0.061472803,-0.015405532,0.08601215,0.065056644,-0.042956296,-0.005627748,-0.008990709,0.02298386,-0.0004868671,-0.007478776,-0.019151142,0.007964088,0.0040815948,0.05948178,0.05858582,-0.007472554,0.0698351,-0.028571164,-0.017371666,-0.008492953,0.02215012,-0.005842405,0.035465077,0.056296144,-0.022336777,-0.063862026,-0.011765695,0.027301889,0.001645704,-0.0118092485,0.04101505,0.024614008,0.011852803,-0.0036740575,0.0012490551,0.007472554,0.07053195,0.018304957,0.015380644,-0.01699835,-0.01664992,0.022510992,0.058436494,-0.045818392,0.014584236,0.0010203987,0.01750855,-0.08073594,-0.0035558408,-0.0006124726,-0.046141934,-0.0250371,0.030686626,0.040442634,-0.023419395,0.00707435,0.05