	('88acfa0c-9d9c-4ab1-a399-6364b35bbc8d', 'Presentation Skills', 'CORP089', 'This corporate training program on Presentation Skills helps participants understand key principles, explore practical workplace examples, and build confidence applying presentation skills in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765254338055-1eog100c00xi.jpg', 'Active', '5 weeks', 0, 0, 0, 5, 5, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:21.900388+00', NULL, '["Explain the core concepts and importance of Presentation Skills in a professional environment.", "Recognize common workplace situations where strong presentation skills is critical to success.", "Apply tools, techniques, and best practices related to presentation skills in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in presentation skills.", "Demonstrate growth in key skills developed in this course: Presentation Skills, Communication, Active Listening, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.0063376883,0.008742395,0.058019705,-0.0024403112,-0.016290653,-0.008435644,-0.009969397,0.05709945,0.022305157,0.039198358,0.038234282,-0.036700528,-0.011798946,-0.036831994,0.013738049,0.01117449,-0.014220086,-0.0037029192,0.013705183,0.031836342,0.03698537,0.010582899,0.0005364714,0.08282269,-0.011766081,0.038650587,-0.014220086,0.035670724,0.0075811245,0.032033537,0.014252952,-0.017550522,-0.022743372,-0.016904155,0.03527633,0.02896603,-0.06612669,0.021308217,-0.0146035245,-0.009777678,0.006135014,0.019139053,0.020694716,0.02222847,0.021100067,0.040775932,0.015885305,-0.024824895,0.021614969,0.045793496,-0.053286977,0.011787991,0.01824071,-0.016235877,-0.035188686,-0.016663136,-8.430509e-05,-0.033786397,-0.041236058,-0.017583389,0.08133276,-0.027651384,0.012817797,0.06752898,-0.016958931,