	('57560c8c-1c54-44d5-b5d9-07671dae9c67', 'Sales Fundamentals', 'CORP093', 'This corporate training program on Sales Fundamentals helps participants understand key principles, explore practical workplace examples, and build confidence applying sales fundamentals in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765254360472-0z08udldd05.jpg', 'Active', '4 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:42.122041+00', NULL, '["Explain the core concepts and importance of Sales Fundamentals in a professional environment.", "Recognize common workplace situations where strong sales fundamentals is critical to success.", "Apply tools, techniques, and best practices related to sales fundamentals in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in sales fundamentals.", "Demonstrate growth in key skills developed in this course: Sales Fundamentals, Sales Skills, Customer Focus, Negotiation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.025203073,0.028769322,0.062564895,-0.010932103,0.020655511,-0.026519474,-0.0145163005,0.03233557,0.031162776,0.05662913,0.08233483,-0.06969739,-0.024137987,-0.034681153,0.0461458,0.020787152,-0.009454145,0.008718157,-0.015820732,-0.0035064106,0.06184686,0.00417957,-0.009214799,0.06998461,-0.027141772,-0.012577603,0.0065281466,0.019075831,-0.05035828,-0.01635926,0.061416037,-0.023587493,-0.041167416,0.0047270725,0.020105017,0.053278293,-0.016526802,0.04741433,-0.0022797652,-0.009226766,-0.009795212,0.009137012,-0.0016006225,0.032909997,0.013738428,0.025346681,0.014324824,-0.010016606,-0.009280619,0.027524725,-0.054666497,0.007820612,0.050741233,0.005917816,-0.038199533,0.041382827,-0.007844547,-0.02628013,-0.013570886,0.026782755,0.0150069585,-0.0342264,0.0035512878,0.032072287,-0.012146781,