	('a6b79a91-1c2f-4b23-b05f-a15ad65e0b5f', 'Servant Leadership', 'CORP094', 'This corporate training program on Servant Leadership helps participants understand key principles, explore practical workplace examples, and build confidence applying servant leadership in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765253771218-zdi595wknk.jpg', 'Active', '6 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:47.939884+00', NULL, '["Explain the core concepts and importance of Servant Leadership in a professional environment.", "Recognize common workplace situations where strong servant leadership is critical to success.", "Apply tools, techniques, and best practices related to servant leadership in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in servant leadership.", "Demonstrate growth in key skills developed in this course: Servant Leadership, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.004116582,-0.0068079666,0.054699305,-0.011831492,-0.026101133,0.012014059,-0.0119905025,0.058656875,0.025111739,0.036536872,0.05724346,-0.052202266,-0.0072143245,-0.049092744,0.004575943,0.0073438883,0.011860939,0.016572334,0.04652503,0.025441537,0.06713739,0.0039722957,0.025865562,0.10101233,-0.047019728,0.009664251,-0.019705413,0.044711147,-0.016442772,-0.03392205,0.028951528,-0.012485199,-0.03929304,-0.019340279,0.040918473,0.031330783,0.011219011,0.011825603,0.009069437,0.030105818,-0.014899789,0.0067196283,0.022249566,0.03641909,0.004973467,-0.030930312,0.00033605503,-0.012496977,0.017290823,0.01886914,0.00087381667,0.019198937,0.026572272,0.006295603,-0.029564008,0.008209607,-0.013121237,0.016890354,-0.03962284,0.014958682,0.04047089,-0.04110693,0.0044876044,0.06916329,0.011342686,