	('d8c0d05b-78c1-43c9-94a5-dd6d8cd7f779', 'Social Media Marketing', 'CORP095', 'This corporate training program on Social Media Marketing helps participants understand key principles, explore practical workplace examples, and build confidence applying social media marketing in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765253805285-0wawcaa5ebir.jpg', 'Active', '4 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:56.180233+00', NULL, '["Explain the core concepts and importance of Social Media Marketing in a professional environment.", "Recognize common workplace situations where strong social media marketing is critical to success.", "Apply tools, techniques, and best practices related to social media marketing in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in social media marketing.", "Demonstrate growth in key skills developed in this course: Social Media Marketing, Sales Skills, Customer Focus, Negotiation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.00660563,0.042889073,0.016276462,0.020054502,0.0024993874,-0.003852294,0.008833248,0.04094065,0.022359345,0.048853148,0.045170154,-0.066864185,-0.017999154,-0.011660838,0.015219086,0.015183444,-0.028180853,-0.026588848,0.043887045,-0.011482628,0.08026553,0.046144366,-0.014363681,0.080835804,-0.03267173,0.024200842,-0.015623027,0.031246055,-0.028727362,0.024759231,0.01981689,-0.03319448,-0.055838957,-0.021860357,0.04923333,0.0065640477,-0.023630572,0.02925011,0.01321126,0.019104052,-0.02287021,0.00039911488,0.01792787,0.04345934,-0.022169255,0.015908163,-0.015230967,-0.01548046,0.06339504,0.056456752,-0.04890067,-0.006326435,0.008132291,-0.003510726,-0.06928783,0.0031750982,-0.028038286,-0.019401068,-0.033669703,0.024141438,0.03982387,-0.039301123,0.018367453