	('562fc65b-14ab-4f2f-be72-89088ec69d2e', 'Trade Show Staff Training', 'CORP098', 'This corporate training program on Trade Show Staff Training helps participants understand key principles, explore practical workplace examples, and build confidence applying trade show staff training in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765253752806-3de6og9xwcx.jpg', 'Active', '5 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:01:28.143351+00', NULL, '["Explain the core concepts and importance of Trade Show Staff Training in a professional environment.", "Recognize common workplace situations where strong trade show staff training is critical to success.", "Apply tools, techniques, and best practices related to trade show staff training in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in trade show staff training.", "Demonstrate growth in key skills developed in this course: Trade Show Staff Training, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.00013522463,0.03799923,0.02034198,-0.02671821,-0.020122556,-0.012003833,-0.0006780391,0.025659807,0.016082555,0.049331885,0.05284268,-0.018225174,0.013397827,-0.04122607,0.034540065,-0.013630159,4.8654652e-05,-0.008718913,-0.019412652,0.013552715,0.053849455,0.03376562,0.016495591,0.018470414,-0.020122556,0.026111566,-0.012158722,0.009396549,0.028499424,0.017592715,0.022136101,-0.027002173,-0.0031526198,-0.012887986,0.0370699,0.021813419,0.018160637,0.028576868,0.021735974,-0.009131948,-0.0019361022,0.0014827315,0.012752459,0.02589214,0.021955399,-0.0120748235,-0.029222235,0.00074297923,0.0048725237,0.039289966,-0.013217124,0.024394887,0.027518466,-0.027750798,-0.039496485,-0.019580446,-0.018354248,-0.040993735,-0.018973801,0.0063794567,0.06618888,-0.022949265,0.020909904,0.0639