	('9be5f3a6-ef2c-406e-9fa6-2a6002f770bb', 'Employee Motivation', 'CORP103', 'This corporate training program on Employee Motivation helps participants understand key principles, explore practical workplace examples, and build confidence applying employee motivation in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765253306999-hf98lyszde.jpg', 'Active', '5 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:57:46.34588+00', NULL, '["Explain the core concepts and importance of Employee Motivation in a professional environment.", "Recognize common workplace situations where strong employee motivation is critical to success.", "Apply tools, techniques, and best practices related to employee motivation in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in employee motivation.", "Demonstrate growth in key skills developed in this course: Employee Motivation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.0010842893,0.025829919,0.01816751,0.0034334606,0.00046756773,0.019816976,0.026251059,0.071547,0.034556877,0.015453498,0.08240306,-0.045085374,-0.025104623,-0.03537576,0.0043196096,-0.0033281757,0.018623745,-0.0138742225,0.008861487,-0.0023191946,0.04272231,0.008364308,0.0008941913,0.08829901,-0.023911392,0.023022318,-0.027678255,0.023981582,-0.030345475,-0.043237038,0.03481424,-0.0045652743,-0.05240853,-0.028263172,0.03109417,0.020249814,-0.02042529,0.009926035,0.006042189,-0.008662616,-0.005644446,-0.009715466,0.05320402,0.056947485,-0.029222436,-0.022495894,-0.016950885,0.003529972,0.012470423,0.0059895464,-0.0589596,0.030813409,0.0287779,-0.016108604,-0.04384535,0.014482536,-0.014751598,-0.009867543,-0.047682405,0.020448687,0.04232457,-0.046746537,0.028473742,0.06574463,0.012306646,0.023712521,-0.012271551,-0.011195305,-0.02