	('dededcea-1f40-4805-bba8-58dfbd78abc6', 'Facilitation Skills', 'CORP104', 'This corporate training program on Facilitation Skills helps participants understand key principles, explore practical workplace examples, and build confidence applying facilitation skills in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765253353198-jjoltg9dqu.jpg', 'Active', '5 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:58:02.92715+00', NULL, '["Explain the core concepts and importance of Facilitation Skills in a professional environment.", "Recognize common workplace situations where strong facilitation skills is critical to success.", "Apply tools, techniques, and best practices related to facilitation skills in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in facilitation skills.", "Demonstrate growth in key skills developed in this course: Facilitation Skills, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.002808794,0.004943358,0.06596713,0.012720868,-0.00034755655,0.011473841,-0.010948777,0.046181764,0.037375007,0.027088528,0.05346106,-0.06615806,0.02859212,-0.03286423,0.013341398,0.055895448,-0.028902385,0.008490523,0.032410767,0.008037059,0.048401352,-0.0027476358,-0.010095548,0.06787645,-0.047637623,-0.009540651,0.01440346,0.057088774,-0.02326988,0.014128994,0.02859212,-0.014140927,-0.04828202,-0.007911759,0.0192961,0.037661407,-0.029594515,0.0324585,-0.015155256,0.011975039,0.00026365073,0.016825914,0.015930919,0.029880913,0.04930828,-0.0026178616,-0.009791249,0.028544387,0.023448879,0.019009702,-0.042434715,0.0013208641,0.022840282,-0.032959696,-0.03093104,0.017458377,-0.0024373708,-0.04744669,-0.06663539,0.022291353,0.055895448,-0.026038399,0.014725658,0.043055248,-0.010710112,0.048043355,-0.018174373,-0.009385519,-0.0175