	('354eaca3-2ecc-44de-b3f3-833eeac79309', 'Office Politics For Managers', 'CORP110', 'This corporate training program on Office Politics For Managers helps participants understand key principles, explore practical workplace examples, and build confidence applying office politics for managers in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765252082369-c3fugujsdg.jpg', 'Active', '6 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:06.430143+00', NULL, '["Explain the core concepts and importance of Office Politics For Managers in a professional environment.", "Recognize common workplace situations where strong office politics for managers is critical to success.", "Apply tools, techniques, and best practices related to office politics for managers in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in office politics for managers.", "Demonstrate growth in key skills developed in this course: Office Politics For Managers, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.03137356,0.06612984,0.023631413,0.001421875,-0.009546662,-0.023988742,-0.005035373,0.030349214,0.009332264,0.044142146,0.049168583,-0.031873822,-0.008087565,-0.036114134,0.014984031,-0.018057067,-0.0013035095,-0.008855824,-0.00072657067,0.022082984,0.020558376,0.06403351,0.015031675,0.066796854,-0.016460994,0.040521204,0.0034273886,0.06312827,0.007682591,0.005758966,0.05197958,-0.040211517,-0.017556805,-0.0016452061,0.019093323,-0.012756675,-0.025823036,-0.0011695108,0.03530419,0.035518587,-0.010320877,0.029277224,0.016556282,0.048692144,-0.002026358,0.01964123,0.016842145,-0.013507067,0.032183506,-0.0030641032,-0.040568847,0.015043586,-0.0081471205,0.000870247,-0.007098953,0.0455,-0.022202093,0.006089496,-0