	('a7616e5f-e242-4ef4-8c5c-2f57e18ed450', 'Performance Management', 'CORP111', 'This corporate training program on Performance Management helps participants understand key principles, explore practical workplace examples, and build confidence applying performance management in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765252049725-fol9nw0qbeg.jpg', 'Active', '4 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:14.21023+00', NULL, '["Explain the core concepts and importance of Performance Management in a professional environment.", "Recognize common workplace situations where strong performance management is critical to success.", "Apply tools, techniques, and best practices related to performance management in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in performance management.", "Demonstrate growth in key skills developed in this course: Performance Management, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.017474592,0.039710715,0.07252542,0.003415755,0.0010386534,0.009763489,-0.0038555516,0.015903052,0.035089917,0.037693515,0.05779516,-0.030445665,-0.019738078,-0.06544176,0.034972638,0.0027692537,-0.014437062,-0.01043198,0.030703679,0.02563722,0.05268179,0.04996091,0.0013890248,0.061266623,-0.03175919,0.00514269,-0.052212674,0.053948402,-0.01416732,-0.009259188,0.030516032,-0.016266616,-0.03968726,-0.03466771,0.04874121,0.0008891225,-0.006116107,0.033072717,0.004271893,-0.0035623538,-0.06032839,-0.009458562,-0.00032361713,0.04341674,-0.002443804,0.008907351,0.02001955,0.0016653638,0.03457389,0.019034404,-0.044871,0.030000003,-0.0052629015,0.013463645,0.014437062,0.024534795,-0.0038702115,-0.007734559,-0.0267631,0.008068805,0.041985933,-0.04564504,0.001086298