	('a543a10d-f6d8-40da-9234-2a35ca85ca16', 'Team Building For Managers', 'CORP137', 'This corporate training program on Team Building For Managers helps participants understand key principles, explore practical workplace examples, and build confidence applying team building for managers in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765258804242-recrwan7w1r.webp', 'Active', '4 weeks', 0, 0, 0, 9, 9, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:01:07.346893+00', NULL, '["Explain the core concepts and importance of Team Building For Managers in a professional environment.", "Recognize common workplace situations where strong team building for managers is critical to success.", "Apply tools, techniques, and best practices related to team building for managers in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in team building for managers.", "Demonstrate growth in key skills developed in this course: Team Building For Managers, Leadership, People Management, Decision Making, Collaboration, Teamwork, Facilitation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.004394634,0.055933826,0.06853995,-0.015524205,-0.050424486,-0.010306671,0.011672335,0.02404501,-0.0073769153,0.029764453,0.05135827,-0.040012762,-0.005048285,-0.06214351,0.030488137,0.0056960993,0.0062855524,-0.03963925,-0.0048265103,0.0025533233,0.03744485,0.04038628,0.016376285,0.07115455,-0.012944619,0.026776336,-0.028690599,0.059902422,-0.01484721,0.004394634,0.010645169,-0.0154658435,-0.02364815,0.011754041,0.057567954,0.015617584,-0.01639963,0.008129781,0.007779611,0.019714573,0.003180711,0.015174035,0.00767456,0.035623964,-0.014298609,-0.01635294,0.018594028,0.005518096,0.013084687,-0.020625016,-0.01614284,0.019165974,0.0018340156,0.014181887,-0.011964143,0.00254311,-0.0175785