	('b4b5814a-3e09-4996-80a7-1b58ef140407', 'Lean Six Sigma', 'CORP107', 'This corporate training program on Lean Six Sigma helps participants understand key principles, explore practical workplace examples, and build confidence applying lean six sigma in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765252366950-z01dslyu4jc.jpg', 'Active', '6 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:59:12.951565+00', NULL, '["Explain the core concepts and importance of Lean Six Sigma in a professional environment.", "Recognize common workplace situations where strong lean six sigma is critical to success.", "Apply tools, techniques, and best practices related to lean six sigma in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in lean six sigma.", "Demonstrate growth in key skills developed in this course: Lean Six Sigma, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.0009912577,0.014930726,0.033144522,-0.01535318,0.0012326599,-0.021629637,-0.017211976,0.04321099,0.0011753269,0.020277783,0.045069788,-0.05286708,-0.045552593,-0.039300278,0.07797291,0.017996533,0.00013343128,-0.006198001,-0.023959167,0.010579451,0.061267875,0.02546793,0.038117405,0.1011958,0.011110536,-0.018865582,0.02086922,0.0111588165,-0.008437007,-0.014834165,0.044466283,-0.0186966,-0.028461318,-0.022522824,0.027085327,0.013590943,0.023500504,0.063440494,0.017308537,0.03741734,-0.0028530722,0.026361119,0.0024291095,0.042679906,0.030151134,-0.026988765,0.050694462,-0.058419332,0.035896506,0.028147496,0.02188311,-0.009245704,0.038165685,0.01668089,-0.009879385,-0.001736587,-0.021762408,-0.003786997,-0.00821371,-0.009806964,0.034448095,-0.055522505,-0.013035718,0.027302587,0.042969592,0.015703212,0.0031714214,0.0009806964,-0.0110019045,-0.07734526,0.025564492,0.0