	('c3a3f4fc-6037-4340-8520-9855ec69e533', 'Business Writing', 'CORP006', 'This corporate training program on Business Writing helps participants understand key principles, explore practical workplace examples, and build confidence applying business writing in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765170142997-riadlsqsr0o.webp', 'Active', '5 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:56:18.887174+00', NULL, '["Explain the core concepts and importance of Business Writing in a professional environment.", "Recognize common workplace situations where strong business writing is critical to success.", "Apply tools, techniques, and best practices related to business writing in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in business writing.", "Demonstrate growth in key skills developed in this course: Business Writing, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.013421156,0.044460464,0.0990675,0.0039548595,-0.004934927,-0.04026347,0.001452085,0.04768892,0.016591962,0.043538045,0.021273224,0.000489313,-0.042684812,-0.004427598,0.01987807,0.084723935,0.010238821,0.040655497,0.011143941,0.0110516995,0.037219495,0.007327444,-0.013305854,0.06867389,-0.029886287,0.030024648,-0.05013332,-0.00652033,-0.008117263,-0.023487024,0.037796006,-0.01308678,-0.011466787,-0.008947438,0.024282608,0.02668089,-0.004139343,0.025804594,0.025412567,-0.010648143,-0.011593619,0.011829988,0.019428393,0.030209132,-0.03175418,0.05691308,-0.014920083,0.044737186,0.03406022,0.010763444,-0.04948763,0.02898693,0.016003922,-0.017998647,-0.032192327,-0.008543881,-0.0147586595,-0.019047895,-0.04369947,-0.007281323,0.052024275,-0.04323826,-0.050363928,0.033944916,-0.0011796838,0.008336336,0.005678625,-0.008440109,0.00065109617,-0.048057888,0