	('d09a8549-6220-41c6-9f5a-8c9cc2f7f620', 'Contract Management', 'CORP031', 'This corporate training program on Contract Management helps participants understand key principles, explore practical workplace examples, and build confidence applying contract management in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765255928976-7cns24yw4j2.jpg', 'Active', '4 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:56:41.54083+00', NULL, '["Explain the core concepts and importance of Contract Management in a professional environment.", "Recognize common workplace situations where strong contract management is critical to success.", "Apply tools, techniques, and best practices related to contract management in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in contract management.", "Demonstrate growth in key skills developed in this course: Contract Management, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.009011243,0.054925665,0.07728826,0.009256446,-0.02212965,0.018856177,-0.018794877,0.021271436,0.0123214945,0.0405322,0.051100485,-0.049335018,0.019763432,-0.01585243,0.031901024,0.014307646,-0.022056088,0.028051322,0.014050182,0.01771598,0.050364874,0.034549225,0.007895565,0.07145241,-0.042714514,-0.0029868896,-0.026310375,0.01904008,-0.016440919,-0.0076442305,0.06546944,-0.017863102,-0.03918358,-0.030846646,0.037123866,0.047177225,0.009630382,0.017409476,-0.013044846,-0.0091522345,-0.045092992,0.0074480674,0.02606517,0.043352045,-0.016759684,-0.002692645,-0.013253269,0.039772067,0.011089345,0.038104683,-0.0630174,-0.004499491,0.033789095,-0.0017225572,-0.034083337,0.010034968,-0.02406676,0.025795447,-0.03165582,0.01577887,0.02596709,-0.053405404,-0.0068105375,0.060418233,-0.016