	('5200198c-b827-4444-b75b-23ee9a6dab1d', 'Supervising Others', 'CORP113', 'This corporate training program on Supervising Others helps participants understand key principles, explore practical workplace examples, and build confidence applying supervising others in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765251627535-2u5xrvs2og8.jpg', 'Active', '6 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:59.738998+00', NULL, '["Explain the core concepts and importance of Supervising Others in a professional environment.", "Recognize common workplace situations where strong supervising others is critical to success.", "Apply tools, techniques, and best practices related to supervising others in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in supervising others.", "Demonstrate growth in key skills developed in this course: Supervising Others, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.007946146,0.01415443,0.06091664,-0.0128395995,-0.031372983,0.032493446,0.05227306,0.033568177,0.019653847,0.021208776,0.04022236,-0.050489467,-0.027599994,-0.020945812,0.012782433,-0.006688482,-0.0056794933,-0.0058224094,0.065535694,0.028491791,0.036197837,0.022272075,0.043034952,0.06004771,-0.02378127,-0.014257329,-0.0014534587,0.06283744,-0.010158489,-0.0054879854,0.02647953,-0.017424354,-0.08071912,-0.014028663,0.024878867,0.009203809,0.04049676,0.025747798,0.010913088,-0.0058224094,0.013925763,0.024856001,0.037089635,0.027874393,-0.00751168,0.0149776265,0.017207121,-0.010615822,0.026022198,0.01883065,-0.022283508,0.0032584914,-0.002632518,0.028949123,0.0022852314,0.03004672,0.017664453,0.014245896,-0.051769994,-0.0250618,0.061145306,-0.035580438,0.011570503,0.055017054,0.019002149,