	('73c8e74b-de12-4c16-aa0c-d73415e6e87d', 'Workplace Violence', 'CORP051', 'This corporate training program on Workplace Violence helps participants understand key principles, explore practical workplace examples, and build confidence applying workplace violence in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256460919-yhod3drlys.jpg', 'Active', '5 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:01:48.727813+00', NULL, '["Explain the core concepts and importance of Workplace Violence in a professional environment.", "Recognize common workplace situations where strong workplace violence is critical to success.", "Apply tools, techniques, and best practices related to workplace violence in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in workplace violence.", "Demonstrate growth in key skills developed in this course: Workplace Violence, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.012608648,0.052575685,0.05086281,0.010895776,-0.04184644,-0.012775178,0.012025796,0.02094701,0.031854678,0.049768478,0.063709356,0.015748916,-0.007785246,-0.033401024,0.023123786,0.03363892,0.018710759,0.039396077,0.0029187237,-0.015011429,0.00095456984,0.0365175,-0.02417054,0.07755508,-0.031212352,0.0063221664,-0.0010296567,0.047746334,-0.0012809376,-0.0038093582,0.052052308,-0.016070079,-0.0487693,-0.009153165,0.02697775,-0.014154992,-0.004413027,0.040181145,0.013488875,0.008088567,-0.0021128408,-0.011526207,-0.0014980204,0.052195046,-0.023218945,0.0021009457,0.012311274,0.019043816,0.0023670953,0.003821253,0.01465458,-0.012370749,0.0034644045,0.022719357,-0.050244275,0.011419153,-0.02195808,0.012501594,-0.027881766,-0.012031743,0.061568268,-0.049245097,-0.012430224,0.024598759,0.029666008,0.0068931244,-4.1980813e-05,-0.023861272,0