	('24c2b4e7-ce7e-4211-aef3-2da9fb47b3f1', 'Digital Citizenship', 'CORP018', 'This corporate training program on Digital Citizenship helps participants understand key principles, explore practical workplace examples, and build confidence applying digital citizenship in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765170528601-yuj52don2ah.webp', 'Active', '4 weeks', 1, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:57:08.777535+00', NULL, '["Explain the core concepts and importance of Digital Citizenship in a professional environment.", "Recognize common workplace situations where strong digital citizenship is critical to success.", "Apply tools, techniques, and best practices related to digital citizenship in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in digital citizenship.", "Demonstrate growth in key skills developed in this course: Digital Citizenship, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.015911326,0.027011145,0.04482802,0.032489594,0.026225105,0.008396321,0.022163907,0.08312953,0.0013562143,0.07636484,0.03601486,-0.0359434,-0.0026424592,-0.077794,0.029297803,0.037229646,-0.02309286,0.0023536496,0.04077873,0.05135452,0.07488804,0.04925842,0.005651141,0.082986616,-0.053069513,0.0051420024,-0.02501032,0.01580414,-0.0118263075,0.0073601794,0.027368434,-0.027821003,-0.04549496,-0.054546315,0.05326007,0.011993043,-0.013434114,0.044661283,0.012130004,0.024093274,-0.025343789,-0.010885444,0.019960616,0.023223868,-0.046709746,-0.030036202,-0.0051568896,0.015661223,0.020639468,0.04887731,-0.034418963,0.014863275,0.008539237,0.013291198,-0.039397206,0.009414598,-0.008187902,0.0038081186,-0.07522151,0.01174294,0.055927835,-0.020163082,0.004912741,0.055594366,0.015137197,0.021747068,-0.034966808,-0.008878663,-0.009164495