	('fe6adeb4-a17c-46a1-b03b-9e9d880eac7f', 'Employee Onboarding', 'CORP035', 'This corporate training program on Employee Onboarding helps participants understand key principles, explore practical workplace examples, and build confidence applying employee onboarding in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256069576-q9asxxfn9z.jpg', 'Active', '6 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:57:48.406556+00', NULL, '["Explain the core concepts and importance of Employee Onboarding in a professional environment.", "Recognize common workplace situations where strong employee onboarding is critical to success.", "Apply tools, techniques, and best practices related to employee onboarding in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in employee onboarding.", "Demonstrate growth in key skills developed in this course: Employee Onboarding, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.005629331,0.02661246,0.022303663,0.023039602,-0.012006469,0.0032286304,0.03746161,0.038648605,0.02017894,0.06537976,0.059207384,-0.042589433,-0.022030653,-0.056406073,0.013816639,-0.00667092,-0.011763135,-0.0032137928,0.004362212,0.026113922,0.02656498,-0.00017276363,0.0018724869,0.08389691,-0.014861195,0.009490036,-0.027941896,0.01692657,-0.018552754,-0.05308248,0.039835602,-0.010546464,-0.0532724,-0.011163701,0.031194266,0.0073712477,0.019264953,0.017389499,0.0062020565,-8.763372e-05,-0.010421829,0.017781207,0.044393666,-0.0014726175,-0.027704498,-0.011608825,-0.035396233,0.012439723,0.015620873,0.038292505,-0.027514577,0.01025565,-0.0060151047,0.0045550987,-0.044892207,0.010469309,0.027419617,-0.009104263,-0.051610608,0.010386219,0.07046011,-0.03767527,0.015098595,0.06457261,0.009691826,0.008724424,-0.052037925,0.009822396