	('3ac822fb-ce93-4b2c-a800-ea9beaaa53bc', 'Entrepreneurship', 'CORP019', 'This corporate training program on Entrepreneurship helps participants understand key principles, explore practical workplace examples, and build confidence applying entrepreneurship in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765170747725-69ppynwyc63.webp', 'Active', '2 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:57:53.603598+00', NULL, '["Explain the core concepts and importance of Entrepreneurship in a professional environment.", "Recognize common workplace situations where strong entrepreneurship is critical to success.", "Apply tools, techniques, and best practices related to entrepreneurship in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in entrepreneurship.", "Demonstrate growth in key skills developed in this course: Entrepreneurship, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.0057904427,0.04021207,0.072576724,0.013911331,0.00046148166,0.009149375,0.03562252,0.09597629,0.023411462,0.06644147,0.056739207,-0.051555157,-0.0068308203,-0.060258653,-0.010950714,0.038880385,-0.016622256,-0.01794205,0.0002461607,0.04480162,0.06977068,0.0042090695,0.0012417646,0.06477687,-0.024077304,0.010148138,-0.025872698,0.04884423,-0.0061590336,-0.00055065687,0.038000524,0.0005097849,-0.05255392,-0.008947245,0.029725065,0.002452318,-0.010576178,0.021841979,0.047774125,0.012615318,-0.008578654,-9.135813e-05,0.043398596,0.04496808,-0.02228191,-0.032982934,-0.01829875,-0.010891264,0.013851881,0.025230637,-0.01125391,-9.103301e-05,0.017097859,-0.0091018155,-0.0724816,-0.03471888,-0.020415176,-0.038880385,-0.043755297,0.038737707,0.05830869,-0.038642585,0.026086718,0.061875697,0.0021312872,0.026586099,-0.030581148,0.028821424,-0.020759987,-0.026