	('5d007e5d-3f19-4420-b288-5dfaba060e0d', 'Conducting Annual Employee Reviews', 'CORP101', 'This corporate training program on Conducting Annual Employee Reviews helps participants understand key principles, explore practical workplace examples, and build confidence applying conducting annual employee reviews in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765253256891-izcuyc7r3ak.jpg', 'Active', '2 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:56:33.624914+00', NULL, '["Explain the core concepts and importance of Conducting Annual Employee Reviews in a professional environment.", "Recognize common workplace situations where strong conducting annual employee reviews is critical to success.", "Apply tools, techniques, and best practices related to conducting annual employee reviews in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in conducting annual employee reviews.", "Demonstrate growth in key skills developed in this course: Conducting Annual Employee Reviews, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.012858515,0.06857874,0.074096575,0.02149244,-0.034905203,0.039092842,0.009163539,0.03116096,0.02618506,0.025372166,0.034560338,-0.058873277,0.0017812861,0.020457847,0.0038119832,-0.0042707757,-0.0034178523,0.011312784,0.026850156,-0.00069126836,0.04244295,0.01814233,0.0009922549,0.050399467,-0.016504224,0.015395732,-0.008215162,0.07956514,-0.0028158792,-0.038723342,0.02167719,-0.014077857,-0.06473597,-0.02416514,0.007944197,0.030939262,-0.004929713,-0.013905425,0.033895243,-0.0035040684,0.025495332,0.03719609,0.01814233,0.013720675,0.012291952,-0.0027419797,-0.029953934,-0.006731014,0.031185593,-0.0003949005,-0.045596,0.05360178,0.005936594,-0.0068480214,-0.03155509,-0.001240896,0.0042861714,-0.013794575,-0