	('4bbbcbe1-564a-4057-80c2-48e4986df3f3', 'Event Planning', 'CORP079', 'This corporate training program on Event Planning helps participants understand key principles, explore practical workplace examples, and build confidence applying event planning in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765254894098-93dj576371e.jpg', 'Active', '3 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:57:55.586436+00', NULL, '["Explain the core concepts and importance of Event Planning in a professional environment.", "Recognize common workplace situations where strong event planning is critical to success.", "Apply tools, techniques, and best practices related to event planning in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in event planning.", "Demonstrate growth in key skills developed in this course: Event Planning, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.032856174,0.03182429,0.0578794,-0.014950614,-0.021388173,0.007363911,0.017929012,0.043339193,0.016381184,0.031167636,0.052907586,-0.0049512917,0.029854326,-0.028470661,0.017717944,0.02448383,-0.011995669,0.028376853,0.011415234,0.011233482,0.04029044,0.0060857795,-0.017893834,0.052673068,-0.034544714,-0.0025078924,-0.008729987,0.059145804,0.00402494,0.014950614,0.046106525,-0.0064903256,-0.015959049,-0.025679879,0.05248545,0.028142333,0.0012744666,-0.0046053757,-0.031284895,0.020719793,-0.011239344,0.006208902,0.029103864,0.04350336,0.013097911,0.015794884,-0.029971585,0.036092542,0.013391061,0.025890946,-0.020848779,-0.00048442924,0.030792404,-0.014950614,-0.021739952,-0.011497316,-0.022701483,-0.034661975,-0.045637485,0.028916247,0.07185676,-0.03714788,0.01755378,0.08719433,0.030206105,-0.0007244452,0.021329544,0.0006163464,-0.00058666506,-0.02725116,0.06669733,