	('a4f85cf3-8fcd-4ea8-a9d5-5ff8059cab0f', 'Internet Marketing Fundamentals', 'CORP083', 'This corporate training program on Internet Marketing Fundamentals helps participants understand key principles, explore practical workplace examples, and build confidence applying internet marketing fundamentals in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765254927538-l0xk5s9um9.jpg', 'Active', '5 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:59:02.837946+00', NULL, '["Explain the core concepts and importance of Internet Marketing Fundamentals in a professional environment.", "Recognize common workplace situations where strong internet marketing fundamentals is critical to success.", "Apply tools, techniques, and best practices related to internet marketing fundamentals in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in internet marketing fundamentals.", "Demonstrate growth in key skills developed in this course: Internet Marketing Fundamentals, Sales Skills, Customer Focus, Negotiation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.06472749,0.0419351,0.02321537,-0.004468445,0.008380978,-0.055639543,0.012248192,0.0669028,0.028327342,0.078939505,0.10789527,-0.063470654,-0.013184783,-0.044690493,0.03267796,0.0048249536,-0.03797121,-0.010713392,0.01650817,0.010520031,0.08256502,-0.0020635212,-0.018913094,0.06129534,-0.029197466,-0.011486834,-0.007909661,0.030913543,-0.025161061,-0.012906827,0.045778148,-0.02362626,-0.04162089,0.010447521,0.042515185,0.008151362,-0.027698921,0.036230963,0.004619508,0.007232899,-0.0038037675,0.0014600244,0.0409683,0.022260651,-0.02194644,0.019940322,0.02750556,-0.01816382,0.028665725,0.043022756,-0.055397842,0.0027614324,0.017269528,-0.0015770983,-0.037608657,0.059168376,-0.031686984,-0.00