	('813c1829-f612-4537-b252-0f494c5566ed', 'Proposal Writing', 'CORP090', 'This corporate training program on Proposal Writing helps participants understand key principles, explore practical workplace examples, and build confidence applying proposal writing in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765254251956-4xn37qva4le.jpg', 'Active', '6 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:25.580239+00', NULL, '["Explain the core concepts and importance of Proposal Writing in a professional environment.", "Recognize common workplace situations where strong proposal writing is critical to success.", "Apply tools, techniques, and best practices related to proposal writing in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in proposal writing.", "Demonstrate growth in key skills developed in this course: Proposal Writing, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.00532508,0.0036857475,0.08053633,-0.000976448,-0.008944814,-0.03417293,-0.019110875,0.033952884,0.018901832,0.059456058,0.04458104,-0.020090073,-0.020090073,-0.0036527407,0.037913688,0.04374487,0.026163306,0.0127955945,0.008301184,0.026361346,0.0251511,0.009307887,-0.019143881,0.06126042,0.002519511,0.006034724,-0.026053283,0.026207315,-0.010309091,0.0057706703,0.02776963,-0.019826021,-0.034987096,-0.037363578,0.030564198,0.033402774,-0.0016805908,0.041390393,0.0054185987,-0.0015966988,-0.00734949,0.010375104,0.034194935,0.044691063,0.010787687,0.06671753,-0.00981399,0.015524148,-0.00091456046,0.010347598,-0.017636577,0.012817599,0.039035916,0.0032814154,-0.0017342267,-0.020046065,0.011227777,-0.021135285,-0.038001705,-0.0031356358,0.047925718,-0.049466033,-0.018714795,0.052986745,0.0026460367,0.020079073,-0.02086023,-0.0027051736,0.0047282088,-0.02