	('65bbcacc-57ca-48ed-8e4d-6b5f6289e1d4', 'Self-Leadership', 'CORP112', 'This corporate training program on Self-Leadership helps participants understand key principles, explore practical workplace examples, and build confidence applying self-leadership in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765252012977-kdppxkwf5wc.jpg', 'Active', '2 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:43.812219+00', NULL, '["Explain the core concepts and importance of Self-Leadership in a professional environment.", "Recognize common workplace situations where strong self-leadership is critical to success.", "Apply tools, techniques, and best practices related to self-leadership in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in self-leadership.", "Demonstrate growth in key skills developed in this course: Self-Leadership, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.005410271,-0.004506671,0.06988597,0.011806288,0.00018553548,0.0013058299,-0.015624636,0.060323108,0.026105266,0.049853805,0.040676173,-0.06349562,-0.014650221,-0.06975001,0.018038014,-0.015783262,-0.020508043,-0.0007442663,0.017528145,0.029572371,0.042964917,0.020621348,-5.9030995e-06,0.08892106,-0.017573467,-0.0065319818,-0.01076389,0.050714917,-0.029300442,-0.009426902,0.025584066,-0.009324928,-0.036642548,-0.022479534,0.00057218573,0.03136258,0.029073834,0.018287282,0.008803729,-0.0035747446,-0.023340646,0.0063110385,0.011806288,0.06354094,0.009069994,-0.03446711,0.017709432,0.015352706,0.022298248,0.023680558,-0.026966378,0.0032121714,0.012769373,0.018196639,-0.039407168,0.01961294,-0.021335164,0.00558306,-0.053162288,0.010871529,0.03063743,-0.03868202,-0.01103582,0.04169591,0.026082605,0.0114890365,-0.015