	('d0ef45d8-2ab9-4414-bf81-b5936bc7fe77', 'Social Learning', 'CORP070', 'This corporate training program on Social Learning helps participants understand key principles, explore practical workplace examples, and build confidence applying social learning in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765253874154-5w2gm5oaamp.jpg', 'Active', '3 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:51.65772+00', NULL, '["Explain the core concepts and importance of Social Learning in a professional environment.", "Recognize common workplace situations where strong social learning is critical to success.", "Apply tools, techniques, and best practices related to social learning in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in social learning.", "Demonstrate growth in key skills developed in this course: Social Learning, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.0009829957,-0.009417709,0.0073936754,0.02068086,0.011513179,0.009417709,-0.012203732,0.042647578,0.0053160647,0.043933433,0.029098459,-0.06872189,-0.0075841728,-0.017001882,0.043385755,0.015870804,0.011923939,-0.0028306704,0.036670726,0.020930888,0.04410012,0.015858898,-0.00032704513,0.08781924,-0.021883374,-0.026502933,0.0011801901,0.05038653,-0.029217519,0.0095963,0.02228818,-0.020918982,-0.06200686,0.016037488,0.007590126,0.0096736895,-0.010399961,0.031479675,0.016120832,0.011745348,-0.008084228,-0.0017010812,0.01764481,0.029455641,-0.025764756,-0.00857833,-0.016394671,-0.010048731,0.027407795,0.04102835,-0.026169563,-0.02171669,-0.010048731,-0.008274726,-0.07919924,-0.008596189,-0.021478567,-0.0005327971,-0.053672608,0.0018647898,0.027431607,-0.015489809,0.009018855,0.06338797,0.058387414,-0.00703054,-0.042861886,-0.014346826,-0.020264147,-0.04731476,0.0