	('f1efdd3d-79f6-4874-84a3-369b5bb5a9cb', 'Supply Chain Management', 'CORP012', 'This corporate training program on Supply Chain Management helps participants understand key principles, explore practical workplace examples, and build confidence applying supply chain management in their daily roles.', 'data:image/jpeg;base64,', 'Active', '5 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:01:01.766714+00', NULL, '["Explain the core concepts and importance of Supply Chain Management in a professional environment.", "Recognize common workplace situations where strong supply chain management is critical to success.", "Apply tools, techniques, and best practices related to supply chain management in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in supply chain management.", "Demonstrate growth in key skills developed in this course: Supply Chain Management, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.012880275,0.04641499,0.05809924,-0.00982121,0.0134782875,-0.0036800785,0.021240953,0.028244603,0.0049939817,0.030682655,0.053269137,-0.01734237,-0.03463874,-0.022206975,0.034891747,-0.0058018737,-0.010608977,0.0018889153,0.008228426,0.0061411313,0.06375736,0.047059007,0.011868253,0.07829367,-0.05943327,-0.0027356208,0.014007299,0.03093566,-0.04114788,-0.01588184,0.028681614,-0.020700442,-0.044137944,-0.026450565,0.03318971,0.058605254,0.0015640334,0.034293734,-0.0023546752,0.00041580576,-0.044298947,0.0071359025,-0.013190782,0.040043857,0.030199645,-0.033557717,-0.01592784,-0.0015266576,0.008492932,0.015755337,-0.042481907,0.00105371,0.027370585,0.0012111196,-0.032177687,0.0018616023,0.005554619,0.002857811,-0.0140533,-0.012351264,0.0078489175,-0.058191244,-0.011845253,0.0609053,0.043631934,0.04535697,0.029762635,-0.003182693,-0.0515671,-