	('8e74aa91-1005-42f9-8da9-fc2732b8a985', 'Universal Safety Practices', 'CORP049', 'This corporate training program on Universal Safety Practices helps participants understand key principles, explore practical workplace examples, and build confidence applying universal safety practices in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256507934-t6xquursxi.jpg', 'Active', '5 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:01:35.684537+00', NULL, '["Explain the core concepts and importance of Universal Safety Practices in a professional environment.", "Recognize common workplace situations where strong universal safety practices is critical to success.", "Apply tools, techniques, and best practices related to universal safety practices in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in universal safety practices.", "Demonstrate growth in key skills developed in this course: Universal Safety Practices, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.010400223,0.029580466,0.07325199,0.043321937,-0.019496216,-0.014763341,-0.005674071,0.068357766,0.024968602,0.036357082,0.032081358,-0.039422695,-0.0016336484,-0.011012001,0.050501924,-0.009257341,-0.014104504,0.0084842155,-0.0046253093,-0.0103935,0.030790575,0.0027361931,0.0012983471,0.08325557,-0.038481496,-0.04485474,0.014911244,0.060613062,-0.02339546,0.0034252836,0.050959077,-0.028961966,-0.04238074,0.043752197,0.04582283,0.013983493,-0.010601908,0.050932184,-0.016027234,0.014723005,0.0143330805,-0.029096423,0.021526512,0.008699346,-0.030172074,0.0067867,0.035012513,0.020867674,0.015879331,0.0075161275,0.007428731,-0.026003918,0.017223898,0.039664716,-0.013270873,-0.003526126,-0.007206877,0.01756004,-0.03667978,0.008127905,-0.00638333,-0.025573658,-0.0025731644,0.05