	('f1257b3f-0737-42d7-a7c1-d715157fec22', 'Telephone Etiquette', 'CORP096', 'This corporate training program on Telephone Etiquette helps participants understand key principles, explore practical workplace examples, and build confidence applying telephone etiquette in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765253933129-veweiozklo.jpg', 'Active', '6 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:01:12.575827+00', NULL, '["Explain the core concepts and importance of Telephone Etiquette in a professional environment.", "Recognize common workplace situations where strong telephone etiquette is critical to success.", "Apply tools, techniques, and best practices related to telephone etiquette in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in telephone etiquette.", "Demonstrate growth in key skills developed in this course: Telephone Etiquette, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.013270617,-0.011292963,0.030213142,-0.008896366,-0.012555951,-0.0031051028,0.011465468,0.06850941,0.013714204,0.05254031,0.06722794,-0.06397498,0.011718066,-0.0328993,0.023805788,-0.010448917,-0.0061794007,0.015032641,0.009611032,0.023275949,0.026615167,0.046601184,0.007078895,0.047956586,-0.03026243,0.010448917,-0.017817376,0.06915014,-0.00060608034,-0.0014331836,0.0046915393,-0.03196284,-0.013788135,-0.023202017,0.0046052863,0.020676041,0.034994014,0.015316043,0.010091584,0.007768918,-0.016227858,0.026812315,0.05066739,-0.008489746,-0.048005875,-0.0037858842,0.014145468,0.04058813,0.030927809,0.021957513,0.0030080683,0.022733789,-0.021255167,-0.008766986,0.006986481,-0.027551627,-0.027132684,-0.021846617,0.0026584363,-0.010473561,0.03891236,-0.055990424,-0.023275949,0.05446252,0.00717747,0.03294859,-0.021735718,-0.001672689