	('2fb84006-de5e-498c-b83d-124fde4377aa', 'Coaching And Mentoring', 'CORP100', 'This corporate training program on Coaching And Mentoring helps participants understand key principles, explore practical workplace examples, and build confidence applying coaching and mentoring in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765253516344-6n5y41ecknh.jpg', 'Active', '2 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:56:26.20606+00', NULL, '["Explain the core concepts and importance of Coaching And Mentoring in a professional environment.", "Recognize common workplace situations where strong coaching and mentoring is critical to success.", "Apply tools, techniques, and best practices related to coaching and mentoring in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in coaching and mentoring.", "Demonstrate growth in key skills developed in this course: Coaching And Mentoring, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.0064153024,0.005009768,0.04458052,0.023888253,-0.019572504,0.037512023,0.04716997,0.05146239,0.015291748,0.03454932,0.053655256,-0.040777992,0.0175546,-0.02477473,-0.0022774322,0.016598137,-0.025334612,0.019875772,0.034479335,0.03265972,0.05486833,0.04716997,0.018954301,0.08869447,0.0022468138,-0.00275858,-0.031773243,0.036228962,-0.019035952,-0.023724955,0.048243072,-0.0033709498,-0.07745019,0.008252411,0.03279969,0.003379698,-0.001197037,0.044323906,0.025427924,0.0075059035,-0.012935583,0.012620649,0.05286209,0.05888081,-0.007167642,-0.0011788118,0.0032193153,0.013670426,0.0418511,0.003910418,-0.013250515,0.0200624,0.003820021,-0.005654214,-0.034899246,0.007167642,0.007459247,-0.009646282,-0.032333124,0.016143233,0.017577928,-0.040311426,-0.003516752,0.041057933,0.012072433,0.028157344,-0.016178226,-