	('54befc6f-aee0-426c-b3af-8581a1193514', 'Knowledge Management', 'CORP105', 'This corporate training program on Knowledge Management helps participants understand key principles, explore practical workplace examples, and build confidence applying knowledge management in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765253387067-nabws9f0er.jpg', 'Active', '2 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:59:08.003164+00', NULL, '["Explain the core concepts and importance of Knowledge Management in a professional environment.", "Recognize common workplace situations where strong knowledge management is critical to success.", "Apply tools, techniques, and best practices related to knowledge management in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in knowledge management.", "Demonstrate growth in key skills developed in this course: Knowledge Management, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.0027934066,0.06564579,0.042184107,-0.01268104,-0.00676283,-0.00828784,-0.0023227066,0.0481903,-0.010082658,0.060531143,0.04795568,-0.027637864,-0.0042993533,-0.040049095,0.041996412,0.010622277,-0.021092054,0.007056101,0.024845922,0.015578558,0.04697029,0.015731059,-0.012528539,0.090280555,-0.02998403,0.008323032,-0.052460324,0.018687231,-0.023180144,0.0057393145,0.047275294,-0.010428718,-0.057809588,0.016059522,0.026722858,0.024212457,-0.0024048225,0.035872914,0.007748221,0.006082441,-0.033245206,-0.013126812,0.002712757,0.07118275,-0.022183022,-0.021115515,-0.021080323,0.03160289,0.029655568,0.02215956,-0.022488024,-0.011672188,-0.019250311,-0.007953511,-0.020669743,0.007443219,0.0016775103,-0.0008358225,-0.009777657,0.023449952,0.045632973,-0.05006723,0.014229511,0.065