	('cd84b67d-9f71-4525-a21e-137dc0a6b011', 'Manager Management', 'CORP108', 'This corporate training program on Manager Management helps participants understand key principles, explore practical workplace examples, and build confidence applying manager management in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765252145537-18365a8pk3b.jpg', 'Active', '2 weeks', 1, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-22 07:11:00.122428+00', NULL, '["Explain the core concepts and importance of Manager Management in a professional environment.", "Recognize common workplace situations where strong manager management is critical to success.", "Apply tools, techniques, and best practices related to manager management in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in manager management.", "Demonstrate growth in key skills developed in this course: Manager Management, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.0011303296,0.06100221,0.052782755,-0.021823639,-0.0271341,-0.006474057,0.03659142,0.028594784,-0.0038250168,0.04117154,0.043498732,-0.047484674,-0.033249173,-0.039587066,0.009308779,-0.005168105,-0.027554974,-0.0036145789,0.0128119495,0.03215985,0.049589053,0.066151746,0.026688466,0.06986535,-0.03072392,0.0356754,-0.04213708,0.051445857,-0.011524565,0.00374765,0.043127373,-0.015807593,-0.039413765,0.006758767,0.057140056,0.0032679755,0.011852601,0.029931685,-0.008541299,0.014260257,-0.025920987,0.008559868,0.0019156031,0.047682732,0.0061057913,0.008733169,0.0118402215,0.023309082,0.031838004,0.014359286,-0.02626759,-0.0027480703,0.0015860202,0.0097606005,-0.008169939,0.019174598,0.006375028,-0.0092221275,-0.012960494,0.012638647,0.040824935,-0.04382058,0.001980591,0.08214502,0.01188354