	('f8600bba-90d9-485d-9dc9-b0edd42831ef', 'Communication Strategies', 'CORP014', 'This corporate training program on Communication Strategies helps participants understand key principles, explore practical workplace examples, and build confidence applying communication strategies in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765170257210-y6llavsbzf.webp', 'Active', '6 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:56:31.886758+00', NULL, '["Explain the core concepts and importance of Communication Strategies in a professional environment.", "Recognize common workplace situations where strong communication strategies is critical to success.", "Apply tools, techniques, and best practices related to communication strategies in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in communication strategies.", "Demonstrate growth in key skills developed in this course: Communication Strategies, Communication, Active Listening, Presentation Skills, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.016427414,0.025908776,0.037323456,-0.006650845,-0.029150266,-0.0062456587,0.008734661,0.007478583,-0.022690438,0.041352164,0.03642047,-0.041074324,0.0022907502,0.008005326,0.033780966,-0.0025541214,-0.011379949,0.00285367,0.017098866,0.025445705,0.030678397,0.031072007,-0.014887705,0.09789303,-0.041051168,0.017990276,-0.018395461,0.040564947,-0.041352164,-0.004514934,0.030747859,-0.023512388,-0.04579764,-0.015813846,0.049270663,0.026232924,-0.06436675,0.020305626,-0.0008233966,-0.004943274,0.011831443,0.031303544,0.004882496,-0.004714633,-0.015408659,0.024172261,-0.016786292,-0.008491549,0.035957396,0.032576986,-0.06385738,0.019286873,0.031720307,-0.027992591,-0.03009956,-0.004344177,-0.026418153,-0.013672146,-0.06344061,0.007588562,