	('f70ba8f0-71f6-4853-9271-a4cac8f924a6', 'Developing Emotional Intelligence', 'CORP058', 'This corporate training program on Developing Emotional Intelligence helps participants understand key principles, explore practical workplace examples, and build confidence applying developing emotional intelligence in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765256708960-4ut8jy2ys38.jpg', 'Active', '4 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:57:05.3305+00', NULL, '["Explain the core concepts and importance of Developing Emotional Intelligence in a professional environment.", "Recognize common workplace situations where strong developing emotional intelligence is critical to success.", "Apply tools, techniques, and best practices related to developing emotional intelligence in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in developing emotional intelligence.", "Demonstrate growth in key skills developed in this course: Developing Emotional Intelligence, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.0029762692,0.013376236,0.06187924,0.026888272,0.028517865,0.028178366,0.029423194,0.071702056,-0.012165358,0.064233094,0.07192839,-0.04259573,0.0032903051,-0.057941057,0.03193548,0.025077613,0.022746392,-0.0067390427,0.012776456,0.030486954,0.021128116,0.025733978,-0.017789716,0.088360116,0.0033355716,0.009783212,-0.027838867,0.043863192,-0.022056079,-0.0031403601,0.011712695,-0.015979057,0.0045775697,-0.014655014,0.029015794,0.048797235,-0.028925262,0.03465147,0.0043484084,0.021546831,-0.018604511,0.015854575,0.0038080402,0.051739555,-0.038567018,-0.023764886,0.0068918173,0.015413227,0.05124162,0.009268306,0.0057912767,0.023199055,0.008894858,0.0044049914,-0.032614477,0.021037582,-0.050336294,-0.0155263925,-0.032750