	('384555d5-b457-496e-b9cc-f57df09c486b', 'Change Management', 'CORP121', 'This corporate training program on Change Management helps participants understand key principles, explore practical workplace examples, and build confidence applying change management in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765251288961-m71wmy8rxfa.jpg', 'Active', '2 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:56:22.471607+00', NULL, '["Explain the core concepts and importance of Change Management in a professional environment.", "Recognize common workplace situations where strong change management is critical to success.", "Apply tools, techniques, and best practices related to change management in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in change management.", "Demonstrate growth in key skills developed in this course: Change Management, Leadership, People Management, Decision Making, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.021593468,0.05935241,0.07641859,-0.0033243513,-0.033184253,0.0012081142,0.009054561,0.024271911,0.014755142,0.036787115,0.05973166,7.2405375e-05,-0.025860015,0.0028606604,0.022920838,0.015644006,0.0074309027,0.008853085,0.02932066,0.0093864035,0.02761404,0.041480318,0.017599506,0.10097495,-0.03605232,0.027045168,-0.04897048,0.033255365,-0.019353531,0.0030843578,0.047619406,-0.017291367,-0.043021016,-0.0042072893,0.02448524,0.025267439,-0.033255365,0.028609568,0.015169945,-0.0006155383,-0.0429025,-0.004556909,0.04655277,0.06660554,-0.013036671,-0.005229483,-0.0071109114,0.03299463,-0.007347942,0.02932066,-0.011146354,-0.01934168,-0.0020562387,5.347072e-06,0.01317889,0.008864936,0.012052995,0.014091456,-0.021937162,0.00036239723,0.022766769,-0.06963953,0.007442754,0.04361359,0.020704605,0.0173387