	('be8e39dc-b3af-4f5f-a1a5-e8ae88efce37', 'Risk Assessment and Management', 'CORP135', 'This corporate training program on Risk Assessment and Management helps participants understand key principles, explore practical workplace examples, and build confidence applying risk assessment and management in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765210206348-n92czlujar.jpg', 'Active', '4 weeks', 0, 0, 0, 9, 9, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:00:37.791314+00', NULL, '["Explain the core concepts and importance of Risk Assessment and Management in a professional environment.", "Recognize common workplace situations where strong risk assessment and management is critical to success.", "Apply tools, techniques, and best practices related to risk assessment and management in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in risk assessment and management.", "Demonstrate growth in key skills developed in this course: Risk Assessment and Management, Leadership, People Management, Decision Making, Project Management, Risk Management, Stakeholder Management, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.02174244,0.06642171,0.09165454,0.015295083,-0.031332307,-0.008499845,-0.0042876094,0.027807133,0.025557514,0.04814646,0.03411534,-0.036550492,0.014576132,-0.032515097,0.02393408,-0.007838875,-0.019458035,0.015863284,0.0030700327,0.007798289,0.032677438,0.038057968,-0.0024916837,0.04248763,-0.034231298,-0.009305765,-0.017707044,0.010917604,0.010505947,-0.009955139,0.06275738,-0.023017997,-0.04153676,0.025882201,0.03673603,-0.0019539208,-0.01699969,0.02298321,0.005664631,0.00044825667,-0.03587793,0.003684619,0.03353554,0.068787284,-0.025487939,0.019643571,0.03810435,0.0015944457,0.037918817,0.024351534,-0.04369361,-0.015735729,0.008059