	('f81d481b-a1db-446f-9581-b47e9d3015dc', 'Team Building Through Chemistry', 'CORP114', 'This corporate training program on Team Building Through Chemistry helps participants understand key principles, explore practical workplace examples, and build confidence applying team building through chemistry in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765251595135-ib7afskcpl.jpg', 'Active', '6 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:01:09.087904+00', NULL, '["Explain the core concepts and importance of Team Building Through Chemistry in a professional environment.", "Recognize common workplace situations where strong team building through chemistry is critical to success.", "Apply tools, techniques, and best practices related to team building through chemistry in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in team building through chemistry.", "Demonstrate growth in key skills developed in this course: Team Building Through Chemistry, Collaboration, Teamwork, Facilitation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.01137284,0.011651435,0.05101372,0.02795849,-0.033381794,-0.023154287,0.00980033,0.042445395,-0.040068056,0.02217611,0.05195475,-0.038111705,-0.00760253,-0.05069179,0.026868878,0.017285232,0.004398695,-0.018795831,-0.022795208,0.008834536,0.003569103,0.019625423,-0.006680073,0.0696362,-0.054381616,-0.03249029,-0.011793828,0.012227196,-0.034644756,-0.0017288327,0.03328274,-0.018077677,-0.019860681,-0.018102441,0.017074738,0.034124713,-0.013583022,0.026646001,-0.028726174,0.011156156,0.005113754,0.0033833736,0.0025661634,0.061513633,-0.052004278,-0.02350098,-0.027735615,0.03159879,0.031029219,-0.027289864,-0.01733476,0.022906646,0.016170854,-0.0067296014,-0.04284162,-0.017446198,-0.02066551,0.035