	('b46a4ffa-bdb3-4530-9cc6-e45b855703e6', 'Developing Creativity', 'CORP017', 'This corporate training program on Developing Creativity helps participants understand key principles, explore practical workplace examples, and build confidence applying developing creativity in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765170465023-nex38307g5.webp', 'Active', '6 weeks', 2, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:57:03.434149+00', NULL, '["Explain the core concepts and importance of Developing Creativity in a professional environment.", "Recognize common workplace situations where strong developing creativity is critical to success.", "Apply tools, techniques, and best practices related to developing creativity in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in developing creativity.", "Demonstrate growth in key skills developed in this course: Developing Creativity, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[0.013544563,0.0094116125,0.110372,-0.0062204218,0.013448588,-0.02073074,0.045972336,0.07577278,0.009045705,0.04102959,0.06891052,-0.025721474,-0.001178701,-0.039661936,0.028816689,0.03359148,-0.023909934,-0.0177315,0.017647522,0.020322844,0.043620933,-0.002084471,-0.0014133914,0.111043826,-0.0013436591,0.0069702314,-0.019567035,0.035415016,0.009405614,-0.0014808743,0.005605578,-0.021642508,-0.04662017,0.0035361028,0.030448275,0.04686011,0.008247907,0.032391783,-0.013628542,-0.00074268656,-0.016507812,-0.028048884,0.040117823,0.062336184,0.02593742,-0.03200788,0.0027128118,0.011097184,-0.013664533,0.01741958,-0.029200591,0.03440727,0.023993913,-0.027065134,-0.055617888,0.003149201,-0.029752452,-0.025121626,-0.074861005,0.022950178,0.09271248,-0.022158379,0.014996195,0.028840683,-0.001568602,0.031528,-0.028192846,