	('a655425d-f967-434b-a96a-44f30de9299e', 'Workplace Bullying', 'CORP139', 'This corporate training program on Workplace Bullying helps participants understand key principles, explore practical workplace examples, and build confidence applying workplace bullying in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765250481060-tsxh7cnhla.jpg', 'Active', '4 weeks', 0, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:01:44.618294+00', NULL, '["Explain the core concepts and importance of Workplace Bullying in a professional environment.", "Recognize common workplace situations where strong workplace bullying is critical to success.", "Apply tools, techniques, and best practices related to workplace bullying in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in workplace bullying.", "Demonstrate growth in key skills developed in this course: Workplace Bullying, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.008385988,-0.003917711,0.05387432,0.039640743,-0.028304882,-0.018499015,0.00490873,0.034656674,-0.004760946,0.048820708,0.06082884,-0.023077404,-0.0030252147,-0.043488912,0.01615766,0.025685348,0.018730832,0.0105013205,0.012100859,0.0071863336,0.04914525,0.03484213,-0.004630549,0.098475955,-0.04295573,-0.00982905,-0.018012198,0.028026702,0.006166338,0.015554936,0.015415845,-0.034007587,-0.04279346,0.0042828233,0.036418486,-0.012576085,-0.01110984,0.044416178,0.040289834,0.010078254,-0.011718361,0.008200535,0.039779834,0.069220625,-0.04432345,0.012471766,-0.002147207,0.01520721,0.015253573,0.01670243,-0.013016537,0.0067111086,-0.009371211,0.018638104,-0.065326095,0.024966715,-0.03187487,0.028606245,-0.046201173,-0.022300817,0.037322573,-0.035444852,0.0066009955,0.032918047,-0.0031816913,-0.007279061,-0.011747338,-0.014291531,0.0038481