	('deb56160-f61b-4292-83ab-747b25fc6e34', 'Teamwork And Team Building', 'CORP138', 'This corporate training program on Teamwork And Team Building helps participants understand key principles, explore practical workplace examples, and build confidence applying teamwork and team building in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765212102033-wl4iu61bjw8.jpg', 'Active', '5 weeks', 2, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 06:01:10.788448+00', NULL, '["Explain the core concepts and importance of Teamwork And Team Building in a professional environment.", "Recognize common workplace situations where strong teamwork and team building is critical to success.", "Apply tools, techniques, and best practices related to teamwork and team building in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in teamwork and team building.", "Demonstrate growth in key skills developed in this course: Teamwork And Team Building, Collaboration, Teamwork, Facilitation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.006436524,0.01914137,0.07504045,0.020262716,-0.043911897,6.296619e-08,0.011751702,0.05642611,-0.013994394,0.023144573,0.044136163,-0.03572607,-0.006150581,-0.051940728,0.02397437,0.0237501,-0.006481378,-0.032205045,0.042386863,0.0008452143,0.026351621,0.011919904,-0.01910773,0.07602724,-0.02462475,-0.0043564276,-0.021350421,0.05404886,-0.04088426,-0.0077260714,0.021372847,-0.01151622,-0.0130524635,0.009301562,0.036645576,0.020240288,-0.011964758,0.030231478,0.0073111737,0.017089307,-0.0040873047,0.013220665,0.020610332,0.05804085,-0.021103725,-0.021002803,-0.013097317,0.0043227873,0.013030036,0.001424109,-0.01000801,0.0072326795,-0.0010687825,-0.0002270725,-0.06445495,-0.01271606,-0.012054466,0.005317982,-0.038462155,0.03572607,0.0