	('66f1c674-3dc7-4866-a92d-4ca7de477c5e', 'Customer Support', 'CORP125', 'This corporate training program on Customer Support helps participants understand key principles, explore practical workplace examples, and build confidence applying customer support in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765251043784-skbopchae0m.jpg', 'Active', '5 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:56:54.008631+00', NULL, '["Explain the core concepts and importance of Customer Support in a professional environment.", "Recognize common workplace situations where strong customer support is critical to success.", "Apply tools, techniques, and best practices related to customer support in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in customer support.", "Demonstrate growth in key skills developed in this course: Customer Support, Sales Skills, Customer Focus, Negotiation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.0017552745,1.3550934e-05,0.05360703,0.030741023,-0.01896408,-0.004420801,0.032970697,0.056832943,0.018371083,0.04426138,0.0708277,-0.024977082,-0.0074006165,-0.014457295,0.016615808,0.030456385,-0.008705213,0.017268106,0.019545218,-0.00960064,0.06470796,0.027965792,0.0075251465,0.06717483,-0.01626001,0.015548411,-0.0024327748,0.031239143,-0.01254784,-0.021217473,0.05408143,-0.028202992,-0.05132992,-0.020778654,0.036172885,0.013627097,0.0064636795,0.036220327,0.011539744,0.025285441,-0.00052813895,0.028036952,0.0012816172,0.072582975,-0.029294107,0.01274946,0.0047173,0.003169575,0.00638066,0.029626187,-0.020671915,0.03840256,0.017872963,-0.007720836,-0.013971036,0.0045097508,0.0014913903,0.001747862,-0.046016656,-0.0033741593,0.032614898,-0.06437588,-0.008568823,0.0031043452,0.0033296845,0.06850314,-0.00141