	('5a6140e0-138c-48a4-a2fb-1644d6ce7a7e', 'Customer Service', 'CORP124', 'This corporate training program on Customer Service helps participants understand key principles, explore practical workplace examples, and build confidence applying customer service in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765251065383-mg4mm5gy3yn.jpg', 'Active', '4 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:56:52.266442+00', NULL, '["Explain the core concepts and importance of Customer Service in a professional environment.", "Recognize common workplace situations where strong customer service is critical to success.", "Apply tools, techniques, and best practices related to customer service in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in customer service.", "Demonstrate growth in key skills developed in this course: Customer Service, Sales Skills, Customer Focus, Negotiation, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.006073686,0.020513695,0.040763315,0.012747538,-0.017020725,-0.004186162,-0.005266462,0.0551193,0.01819705,0.05339082,0.07153986,-0.052622605,-0.0032949145,-0.026215276,0.028904023,0.014440008,-0.010424893,0.012591495,0.017368821,-0.008612391,0.061553083,0.013695802,0.006805889,0.07797364,-0.02417471,0.02835187,-0.012363432,0.040931363,-0.015784381,-0.031136643,0.06645045,-0.024234727,-0.05281466,-0.021233894,0.04676498,0.008684411,-0.010983049,0.025447063,0.009068517,0.018389104,-0.026383324,0.026095243,0.020129588,0.056367647,-0.016864682,-0.00068681565,-0.0008447345,0.005782605,0.0067998874,0.04993386,-0.040475234,0.02150997,0.007334036,-0.017224781,-0.029024055,0.0046212827,-0.0046782987,-0.017452843,-0.022422224,0.014007888,0.041939642,-0.05771202,-0.016876685,0.03872275,0.012627505,0.061985206,0.01586