	('c7c4b840-fa7e-4155-b678-cc4bd30cd2ac', 'Collaborative Business Writing', 'CORP007', 'This corporate training program on Collaborative Business Writing helps participants understand key principles, explore practical workplace examples, and build confidence applying collaborative business writing in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765170201626-awz5xg4q8m.webp', 'Active', '4 weeks', 2, 0, 0, 3, 3, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:56:29.949209+00', NULL, '["Explain the core concepts and importance of Collaborative Business Writing in a professional environment.", "Recognize common workplace situations where strong collaborative business writing is critical to success.", "Apply tools, techniques, and best practices related to collaborative business writing in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in collaborative business writing.", "Demonstrate growth in key skills developed in this course: Collaborative Business Writing, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.0009329419,0.032935087,0.09438685,0.0052632852,0.013386597,-0.02212789,0.014103096,0.043300446,-0.006711211,0.04029115,0.008532314,-0.02667766,-0.028803276,0.0070276647,-0.0009157758,0.071172275,0.020826248,0.014986779,0.018784225,-0.019130534,0.030403458,0.0022510022,-0.012801455,0.083066165,-0.03143044,0.008771147,-0.037305735,-0.0010396704,-0.025722329,-0.016407836,0.01160132,-0.018402092,-0.012287964,-0.011165448,0.008060618,0.0384999,-0.0014247888,0.05039379,0.023345938,0.007547127,-0.028062893,0.009786188,0.02414603,0.041198716,-0.028803276,0.015834637,-0.014413579,0.035562254,0.038523782,0.013720963,-0.026988143,0.033890422,0.012765631,-0.026462711,-0.05478832,-0.01362543,-0.0046453043,0.0020733702,-0.06028148,0.00403628,0.05755878