	('cd5b8f0e-74e2-4d6d-9dac-89743602ef2d', 'Conflict Resolution', 'CORP123', 'This corporate training program on Conflict Resolution helps participants understand key principles, explore practical workplace examples, and build confidence applying conflict resolution in their daily roles.', 'https://dpooleduinyyzxgrcwko.supabase.co/storage/v1/object/public/course-images/courses/1765251110999-e1zb0eno3i.jpg', 'Active', '2 weeks', 0, 0, 0, 6, 6, 'de3175cc-13f8-4cba-986a-363a3057a90d', '2025-12-04 00:00:00+00', '2026-01-19 05:56:35.56875+00', NULL, '["Explain the core concepts and importance of Conflict Resolution in a professional environment.", "Recognize common workplace situations where strong conflict resolution is critical to success.", "Apply tools, techniques, and best practices related to conflict resolution in realistic scenarios.", "Create a personal action plan to strengthen your day-to-day performance in conflict resolution.", "Demonstrate growth in key skills developed in this course: Conflict Resolution, Emotional Intelligence, Conflict Management, Resilience, Professionalism, Problem Solving."]', NULL, NULL, 'Corporate Training', 'pending', NULL, NULL, NULL, NULL, NULL, 'soft', NULL, '[-0.014952215,0.043084618,0.06485856,0.021357,-0.016851645,0.0010148628,-0.011390786,0.036621924,0.019689208,0.057677794,0.05197951,-0.032568265,0.0057851523,-0.01190618,0.008645878,0.018032998,0.0015186749,0.0386835,0.026105573,0.04303829,0.04695297,0.014708996,-0.02094005,0.07588452,-0.0059038666,0.05244278,-0.00070323766,0.041416828,-0.0075977175,-0.011332876,0.055268764,-0.0073139616,-0.0277502,-0.036853563,0.02504004,0.038081244,-0.020673668,0.030159233,-0.0155892195,0.018125653,-0.014071993,0.007927801,0.00058416143,0.03462984,-0.045516815,0.010475816,-0.00080421724,0.035927013,0.021275926,0.002964963,-0.007991502,0.028445113,0.007261843,0.0007332782,-0.059577227,0.015542892,-0.01737283,-0.008078366,-0.054620177,-0.0069838776,0.05197951,-0.04259818,-0.011552932,0.03907